/* techniques q15 (55 mục) — R6 sửa lỗi */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q15"]=window.__LIBQ["tien-nghich"]["q15"]||{};window.__LIBQ["tien-nghich"]["q15"]["techniques"]={"updatedAt":"2026-07-14","count":55,"techniques":[{"id":"te-thien","name":"Tê Thiên","cn":"","aliases":["Tê thiên thuật","thuật Tê Thiên","thuật Tê thiên"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cực mạnh (truyền thừa Đạo Cổ)","hePhai":"Đạo Cổ truyền thừa","soHuu":["Con trai Diệp Mịch"],"blurb":"Tê Thiên là thần thông do Đạo Cổ Diệp Mịch truyền thừa cho con trai, lấy vạn vật làm trời, dùng hai tay cổ tộc xé trời. Tới mốc hiện tại, thuật này đã được con trai Diệp Mịch thi triển trong trận chiến với Vương Lâm, xé đôi hư ảnh khổng lồ và xuyên phá thần thông Mộng Hồi Viễn Cổ.","detail":"Tê Thiên là thần thông cực mạnh thuộc truyền thừa của Đạo Cổ Diệp Mịch, được truyền cho con trai ông. Nguyên lý cốt lõi của thuật này là lấy vạn vật làm trời, sau đó dùng hai tay cổ tộc xé trời — tức bất kể đối tượng trước mặt là gì đều bị coi như bầu trời để xé toạc. Trong trận chiến với Vương Lâm, con trai Diệp Mịch đã thi triển Tê Thiên xé đôi bàn chân khổng lồ xuất hiện trong thần thông Mộng Hồi Viễn Cổ, đồng thời xé rách thân thể tu sĩ Bước thứ ba từ mi tâm tới bụng lộ xương cốt. Vương Lâm biết tên thuật này từ truyền thừa của Đạo Cổ nhưng không biết phương pháp thi triển, trong lòng khát vọng muốn đoạt được.","thuocTinh":"Cổ tộc","nguonGoc":"Đạo Cổ Diệp Mịch truyền thừa cho con trai","uyLuc":"Xé rách thân thể tu sĩ Bước thứ ba từ mi tâm tới bụng lộ xương cốt, đồng thời xé đôi hư ảnh khổng lồ và xuyên phá thần thông Mộng Hồi Viễn Cổ.","dacDiem":"Lấy vạn vật làm trời, dùng hai tay cổ tộc xé trời.","congNang":["Xé trời — lấy vạn vật làm trời, dùng hai tay cổ tộc xé toạc mọi thứ trước mặt @c1579","Xuyên phá thần thông đối thủ, xé đôi bàn chân khổng lồ trong Mộng Hồi Viễn Cổ @c1579","Xé rách thân thể tu sĩ Bước thứ ba từ mi tâm tới bụng lộ xương cốt @c1579"],"nguoiTu":[{"ten":"Con trai Diệp Mịch","tuChuong":"@c1579","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1579","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Con trai Diệp Mịch thi triển Tê Thiên trong trận chiến với Vương Lâm, xé đôi bàn chân khổng lồ trong Mộng Hồi Viễn Cổ, xuyên phá tầng tầng hư ảnh, xé rách thân thể Vương Lâm từ mi tâm tới bụng lộ xương cốt.","anchor":"lấy vạn vật làm trời, lấy hai tay của cổ tộc xé trời. Thuật này là Tê thiên"}]},"capNhatToi":"@c1579","nguon":["@c1579"]},{"id":"tinh-khong-la-thien","name":"Tinh không là thiên","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Con trai Diệp Mịch"],"blurb":"Thuật pháp vặn vẹo tinh không, khiến lực lượng kỳ dị từ trên trời truyền xuống gây rối loạn tinh vực, dùng trước khi triển khai Tê Thiên.","detail":"Con trai Diệp Mịch chụp vào tinh không, hô lên khẩu quyết, khiến tinh không bên ngoài Vô Danh Chuyển Luân trận vặn vẹo, có lực lượng kỳ dị từ trên trời truyền xuống làm rối loạn vùng tinh vực.","congNang":["Vặn vẹo tinh không, gây rối loạn tinh vực"],"nguoiTu":[{"ten":"Con trai Diệp Mịch","tuChuong":"@c1579","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1579","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Con trai Diệp Mịch thi triển trước khi dùng Tê Thiên, vặn vẹo tinh không bên ngoài Vô Danh Chuyển Luân trận.","anchor":"Tinh không là thiên"}]},"capNhatToi":"@c1579","nguon":["@c1579"]},{"id":"mong-dao-thuat-mong-hoi-vien-co","name":"Mộng đạo thuật + Mộng hồi viễn cổ (dung hợp)","cn":"梦道术 + 梦回远古","loai":"than-thong","loaiLabel":"Thần thông dung hợp","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Mộng đạo thuật do Vương Lâm tự sáng tạo, được dung hợp với Mộng hồi viễn cổ — thần thông vốn thuộc Thanh Quang Thuẫn — tạo thành thần thông giấc mộng hoàn chỉnh, cho phép Vương Lâm trở thành chúa tể giấc mộng. Nhắm mắt thì hết thảy đều giả, mở mắt thì đối phương rơi vào mộng cảnh, mọi tổn thương trong mộng đều phản ánh lên thân xác thật.","detail":"Mộng đạo thuật là thuật pháp do Vương Lâm tự nghiên cứu, bắt nguồn từ Mộng hồi viễn cổ. Mộng hồi viễn cổ vốn là thần thông của Thanh Quang Thuẫn, dùng ký ức chủ nhân hóa thành giấc mộng để sát nhân, nhưng vì chủ nhân đã chết nên giấc mộng bất biến, không thể sửa đổi. Trong tình thế sinh tử, Vương Lâm dung hợp hai thuật, thay thế vị trí chủ nhân đã mất, lấy khí tức Đạo Cổ cùng tam tộc cổ ngưng tụ thành thần thông mới. Sau khi dung hợp, Vương Lâm có thể tùy ý sửa đổi nội dung giấc mộng và trở thành chúa tể toàn quyền trong mộng cảnh. Lần thi triển đầu tiên, thần thông này biến toàn bộ thiên địa thành đôi mắt khổng lồ của chúa tể, ép chết con trai Diệp Mịch trong mộng.","thuocTinh":"Mộng","nguonGoc":"Mộng đạo thuật (Vương Lâm tự sáng) + Mộng hồi viễn cổ (Thanh Quang Thuẫn)","dacDiem":"Nhắm mắt thì hết thảy đều giả, mở mắt thì đối phương vào mộng; tổn thương trong mộng phản ánh thực tại. Dung hợp khí tức Đạo Cổ và tam tộc cổ, người thi triển trở thành chúa tể giấc mộng, toàn quyền chi phối mộng cảnh.","congNang":["Biến toàn bộ thiên địa thành đôi mắt khổng lồ của chúa tể giấc mộng, kéo đối phương vào mộng cảnh @c1580","Tùy ý sửa đổi nội dung giấc mộng, thay thế vị trí chủ nhân cũ để toàn quyền kiểm soát mộng cảnh @c1580","Tổn thương gây ra trong mộng phản ánh lên thân xác thật của đối phương, có thể ép chết đối phương trong mộng @c1580"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1580","tangDatToi":"Đại thành","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1580","loai":"xuất hiện","importance":"major","giaiDoan":"Dung hợp lần đầu — đại thành","text":"Vương Lâm trong tình thế sinh tử dung hợp Mộng đạo thuật với Mộng hồi viễn cổ, trở thành chúa tể giấc mộng. Biến thiên địa thành đôi mắt khổng lồ nghiền nát con trai Diệp Mịch.","anchor":"Mộng đạo thuật dung hợp với Mộng hồi viễn cổ. Mộng này là mộng của ta."}]},"nguon":["@c1580"],"uyLuc":"Biến toàn bộ thiên địa thành đôi mắt khổng lồ của chúa tể, ép chết con trai Diệp Mịch trong mộng cảnh."},{"id":"tam-chi","name":"Tam chỉ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":[],"blurb":"Ba ngón tay xuyên thấu giết chết Văn thú bước thứ ba, để lại khí tức khiến Vương Lâm cảm thấy mơ hồ quen thuộc.","detail":"Dấu vết ba ngón tay xuyên thấu vào cổ thi thể Văn thú ngàn trượng bước thứ ba trong vùng sâu Phong Tiên giới. Vết thương trí mạng, ba ngón tay chậm rãi xâm nhập xuyên thấu. Khí tức lưu lại trên ba chỉ khiến Vương Lâm cảm thấy mơ hồ quen thuộc, giống như đã gặp ở một nơi nào đó, nhưng chưa xác định được chủ nhân.","congNang":["Ba ngón tay xuyên thấu giết Văn thú bước thứ ba"],"tabs":{"tienTrinh":[{"chuong":"@c1585","loai":"xuất hiện","importance":"normal","giaiDoan":"Phát hiện dấu vết trên thi thể","text":"Vương Lâm phát hiện dấu vết ba ngón tay xuyên thấu trên cổ thi thể Văn thú ngàn trượng bước thứ ba, khí tức lưu lại khiến hắn cảm thấy mơ hồ quen thuộc.","anchor":"Ba chỉ này lưu lại trên người Văn thú một luồng khí tức ta mơ hồ quen thuộc"}]},"nguon":["@c1585"]},{"id":"luc-dai-bon-nguyen","name":"Lục đại bổn nguyên","cn":"","loai":"than-thong","loaiLabel":"Thần thông tổng hợp","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Lục đại bổn nguyên là chiêu thức Vương Lâm đồng thời triệu hồi cả sáu bổn nguyên — lôi, hỏa, sinh, tử, nhân, quả cùng tam đại hư bổn nguyên và sát lục — ngưng tụ toàn bộ vào huyết kiếm, bạo phát thành một kiếm không gì ngăn nổi. Lần đầu thi triển tại @c1586, kiếm chiêu này xuyên phá phong ấn cửa.","detail":"Vương Lâm triển khai sáu bổn nguyên cùng lúc: lôi bổn nguyên xuất từ mắt trái, hỏa bổn nguyên xuất từ mắt phải, sinh–tử–nhân–quả phân bố ở hai tay (trong đó có chân giả bổn nguyên), tam đại hư bổn nguyên cùng sát lục — đạo bổn nguyên thứ sáu — đồng loạt ngưng tụ tại mi tâm rồi dung nhập huyết kiếm. Chiêu thức tổng hợp toàn bộ tu vi, cường hóa nguyên thần lẫn huyết kiếm, tạo ra một kiếm uy lực cực đại xuyên phá phong ấn.","congNang":["Tổng hợp toàn bộ tu vi cường hóa nguyên thần và huyết kiếm, tạo kiếm sắc bén không gì ngăn nổi @c1586","Xuyên phá phong ấn cửa @c1586"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1586","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1586","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển đầy đủ","text":"Vương Lâm lần đầu đồng thời triệu cả sáu bổn nguyên ngưng tụ trong huyết kiếm, bạo phát xuyên qua phong ấn cửa đá nối Tiên Cương đại lục.","anchor":"Sáu đạo bổn nguyên ngưng tụ, trực tiếp nhập vào mi tâm của Vương Lâm"}]},"dinhDanh":"goc","nguon":["@c1586"],"uyLuc":"Một kiếm ngưng tụ sáu bổn nguyên bạo phát xuyên qua phong ấn cửa, không gì ngăn nổi @c1586","dacDiem":"Đòi hỏi đồng thời triệu hồi cả sáu bổn nguyên — lôi, hỏa, sinh, tử, nhân, quả, tam đại hư bổn nguyên và sát lục — ngưng tụ tại mi tâm rồi dung nhập huyết kiếm trong cùng một khoảnh khắc"},{"id":"huyet-tran","name":"Huyết trận","cn":"血陣","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Đạo nhân bảy màu"],"blurb":"Trận pháp do Đạo nhân bảy màu bày ra, đã hoàn thành, dùng để tính toán và truy tìm vị trí người thứ ba đã luân hồi vô số lần.","detail":"Huyết trận đã được hoàn thành trước thời điểm Vương Lâm tiến vào Thái Cổ Tinh Thần. Đạo nhân bảy màu đang tiếp tục sử dụng trận này để tính toán vị trí chính xác của người thứ ba — kẻ đã luân hồi vô số lần mà hắn tìm kiếm suốt vạn vạn năm.","congNang":["Tính toán và truy tìm vị trí người thứ ba đã luân hồi vô số lần"],"nguon":["@c1589"],"tabs":{"tienTrinh":[{"chuong":"@c1589","loai":"xuất hiện","importance":"normal","giaiDoan":"Hoàn thành","text":"Đạo nhân bảy màu tiết lộ huyết trận đã hoàn thành, đang tiếp tục tính toán để xác định vị trí người thứ ba luân hồi vô số lần.","anchor":"Huyết trận đã thành, đang tiếp tục tính toán, không bao lâu nữa ta sẽ biết được người thứ ba luân hồi vô số lần rốt cục ở đâu"}]}},{"id":"an-quyet-dieu-khien-viem-long","name":"Ấn quyết điều khiển viêm long","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Chu Tước","soHuu":["Vương Lâm"],"blurb":"Ấn quyết do Chu Tước đời thứ hai truyền dạy Vương Lâm, chuyên kích hoạt ấn ký khắc sâu trong xương cốt và linh hồn viêm long, gây đau đớn cực độ buộc viêm long khuất phục.","detail":"Ấn quyết này nhắm vào ấn ký nằm trên mi tâm viêm long — ấn ký in rất sâu, khắc vào tận xương cốt lẫn linh hồn. Vương Lâm được Chu Tước đời thứ hai truyền dạy ấn quyết này. Khi phát động, viêm long đau đớn kêu thảm, hoàn toàn không thể phản kháng và buộc phải đầu hàng. Ấn quyết đóng vai trò then chốt trong việc Vương Lâm chế ngự viêm long.","congNang":["Kích hoạt ấn ký trên mi tâm viêm long, gây đau đớn cực độ buộc viêm long khuất phục @c1591"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1591","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1591","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu sử dụng","text":"Vương Lâm thi triển ấn quyết Chu Tước đời thứ hai, kích hoạt ấn ký trên mi tâm viêm long khiến nó đau đớn đầu hàng.","anchor":"Ấn quyết này là Chu Tước đời thứ hai đã dạy hắn để điều khiển viêm long này!"}]},"nguon":["@c1591"],"uyLuc":"Khiến viêm long đau đớn kêu thảm, hoàn toàn không thể phản kháng, buộc phải đầu hàng @c1591","dacDiem":"Nhắm vào ấn ký khắc sâu trong xương cốt và linh hồn viêm long, tác động qua mi tâm"},{"id":"luc-luong-huyet-mach-tien-nhan","name":"Lực lượng huyết mạch tiên nhân","cn":"","loai":"khac","loaiLabel":"Năng lực chủng tộc","phamCap":"Không rõ","hePhai":"Viễn cổ tiên nhân","soHuu":[],"blurb":"Năng lực chủng tộc của viễn cổ tiên nhân, tạo lốc vàng chứa lực lượng huyết mạch trấn áp tu sĩ giới nội từ linh hồn như thiên địch bao phủ.","detail":"Tiên nhân vung tay tạo lốc màu vàng chứa lực lượng huyết mạch, trấn áp linh hồn tu sĩ giới nội. Thanh Lâm, Hồng Sam Tử, Nam Vân Tử đều bị ảnh hưởng phải lui lại; chỉ Thanh Thủy không bị tác động.","congNang":["Trấn áp linh hồn tu sĩ giới nội như thiên địch bao phủ"],"nguon":["@c1593"]},{"id":"kim-quang-huyet-mach-bat-diet-the","name":"Kim quang huyết mạch bất diệt thể","cn":"","loai":"khac","loaiLabel":"Năng lực huyết mạch","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Kim quang phát ra từ giọt máu tiên nhân bất diệt thể mà Vương Lâm ngưng tụ, mang huyết mạch tiên nhân tinh thuần cực điểm, trấn áp tiên nhân.","detail":"Vương Lâm mở mắt phát ra kim quang từ giọt máu tiên nhân bất diệt thể hóa thành, huyết mạch tiên nhân tinh thuần tới cực điểm. Tiên nhân Thất Đạo Tông vốn định hút hắn thành hương hỏa bị trấn áp, hãi hùng lui lại.","congNang":["Phát kim quang chứa huyết mạch tiên nhân tinh thuần cực điểm, trấn áp tiên nhân"],"nguon":["@c1593"]},{"id":"toc-bat-diet-chi","name":"Tộc Bất Diệt Chỉ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Đạo cổ","soHuu":["Vương Lâm"],"blurb":"Tộc Bất Diệt Chỉ là thần thông do Vương Lâm tự sáng tạo, lấy cảm hứng từ tiên nhân bất diệt thể, ngưng tụ toàn bộ lực lượng Đạo cổ vào ngón trỏ để tấn công. Thần thông này lần đầu được thi triển khi Vương Lâm đối kháng chưởng ấn trăm trượng huyền kiếp của Chưởng Tôn.","detail":"Tộc Bất Diệt Chỉ là thần thông Vương Lâm tự nghĩ ra, nguồn gốc cảm hứng trực tiếp từ đặc tính bất diệt của tiên nhân bất diệt thể. Khi thi triển, Vương Lâm kích hoạt Cổ Thần tinh điểm trên mi tâm cùng tinh điểm Cổ Yêu trong mắt trái, ngưng tụ toàn bộ lực lượng Đạo cổ lên một ngón trỏ rồi xuất kích. Đặc tính cốt lõi của thần thông nằm ở khả năng tái tạo: khi ngón trỏ bị hủy diệt, nó tự ngưng tụ trở lại và tiếp tục tấn công, quá trình hủy diệt — tái sinh này có thể lặp lại hơn ngàn lần. Thần thông được Vương Lâm lần đầu sử dụng trong trận đối kháng chưởng ấn trăm trượng huyền kiếp của Chưởng Tôn.","nguonGoc":"Vương Lâm tự nghĩ ra từ tiên nhân bất diệt thể","thuocTinh":"Đạo cổ","congNang":["Ngưng tụ toàn bộ lực lượng Đạo cổ (Cổ Thần tinh điểm + Cổ Yêu tinh điểm) vào ngón trỏ để tấn công @c1595","Ngón trỏ bị hủy diệt sẽ tự ngưng tụ lại, quá trình hủy diệt và tái sinh lặp lại hơn ngàn lần @c1595"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1595","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1595","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm lần đầu sử dụng Tộc Bất Diệt Chỉ đối kháng chưởng ấn trăm trượng huyền kiếp của Chưởng Tôn. Ngón trỏ bị hủy diệt và tái tạo hơn ngàn lần.","anchor":"Lấy tiên nhân bất diệt thể làm linh cảm, tự nghĩ ra thần thông, thuật cổ Tộc Bất Diệt Chỉ"}]},"nguon":["@c1595"],"uyLuc":"Đối kháng được chưởng ấn trăm trượng huyền kiếp của Chưởng Tôn, ngón trỏ trải qua hơn ngàn lần hủy diệt và tái ngưng tụ trong quá trình chống đỡ.","dacDiem":"Mang đặc tính tái tạo bất diệt lấy cảm hứng từ tiên nhân bất diệt thể; cần đồng thời kích hoạt Cổ Thần tinh điểm trên mi tâm và Cổ Yêu tinh điểm trong mắt trái để thi triển."},{"id":"sau-thanh-truong-kiem-bon-nguyen","name":"Sáu thanh trường kiếm bổn nguyên","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Vương Lâm dùng lục đạo bổn nguyên (hỏa, lôi, tam đại bổn nguyên, sát lục bổn nguyên) biến hóa thành sáu thanh trường kiếm hư ảo tấn công đối phương.","detail":"Sáu bổn nguyên biến ảo ra bên ngoài cơ thể, hình thành sáu thanh trường kiếm hư ảo đâm vào mục tiêu, sau đó vỡ tung dung nhập lại cơ thể.","congNang":["Kết hợp sáu bổn nguyên thành kiếm hư ảo tấn công"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1596","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1596","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Vương Lâm dùng lục đạo bổn nguyên biến hóa thành sáu thanh trường kiếm hư ảo đâm vào chưởng ấn Chưởng Tôn, sau đó vỡ tung dung nhập lại cơ thể.","anchor":"Lục đạo bổn nguyên biến ảo ra bên ngoài cơ thể, bất ngờ hình thành sáu thanh trường kiếm bổn nguyên hư ảo"}]},"nguon":["@c1596"]},{"id":"quy-tac-thai-son","name":"Quy tắc Thái Sơ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Chưởng Tôn"],"blurb":"Quy tắc mà Chưởng Tôn nắm giữ, biến hóa giếng khổng lồ dung nạp tinh không, từ trong xuất hiện mặt trời đỏ đậm chứa lực lượng thái sơ.","detail":"Chưởng Tôn biến hóa giếng khổng lồ dung nạp tinh không thành nước giếng, rồi từ trong đó hiện mặt trời đỏ đậm bao phủ bốn phía.","congNang":["Biến hóa giếng khổng lồ dung nạp tinh không","Hiện mặt trời đỏ đậm chứa lực lượng quy tắc thái sơ bao phủ bốn phía"],"nguoiTu":[{"ten":"Chưởng Tôn","tuChuong":"@c1596","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1596","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Chưởng Tôn tung ra giếng khổng lồ dung nạp tinh không kèm mặt trời đỏ đậm chứa quy tắc thái sơn tràn ngập bốn phía để quyết cược với Vương Lâm.","anchor":"Một lực lượng quy tắc thái sơ tràn ngập bốn phía"}]},"nguon":["@c1596"]},{"id":"thai-ngoc-that-thu-an","name":"Thái Ngọc Thất Thủ Ấn","cn":"太玉七手印","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thất Đạo Tông / Đại Hồn Môn","soHuu":["Phàn San Lộ"],"blurb":"Thái Ngọc Thất Thủ Ấn là ấn quyết biến ngọc thủ thành bảy bàn tay giống hệt phủ lên nhau, mỗi tay phát một màu trong bảy màu, phóng ra công kích đối phương. Phàn San Lộ thi triển ấn quyết này từ trong hắc động để đối phó đạo nhân bảy màu, nhưng bị đạo nhân bình thản hóa giải và nhận xét thần thông hắn đạt được chưa phải toàn bộ.","detail":"Phàn San Lộ từ trong hắc động vươn ngọc thủ bắt ấn quyết, thi triển Thái Ngọc Thất Thủ Ấn để đỡ chỉ phong bảy màu của đạo nhân bảy màu. Khi ấn quyết phát động, bàn tay hóa thành bảy bàn tay giống hệt nhau phủ lên nhau, mỗi tay phát ra một màu khác nhau trong bảy sắc, bay lao thẳng về phía đối thủ. Đạo nhân bảy màu bình thản hóa giải đòn công kích này, đồng thời nhận ra tên ấn quyết và nhận xét rằng thần thông Phàn San Lộ đạt được không phải toàn bộ — cho thấy bản thân đạo nhân cũng am tường ấn pháp này nhưng Phàn San Lộ chỉ lĩnh hội được phần chưa trọn vẹn.","congNang":["Hóa ngọc thủ thành bảy bàn tay giống hệt nhau phủ lên nhau, mỗi tay phát ra một màu trong bảy màu, phóng ra công kích đối phương @c1597"],"nguoiTu":[{"ten":"Phàn San Lộ","tuChuong":"@c1597","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1597","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Phàn San Lộ thi triển từ hắc động đỡ chỉ phong bảy màu của đạo nhân bảy màu. Đạo nhân hóa giải, nhận ra tên ấn quyết, nói thần thông hắn đạt được không toàn bộ.","anchor":"Thái Ngọc Thất Thủ Ấn….chắc là tên như thế….đáng tiếc thần thông ta đạt được không phải là toàn bộ"}]},"nguon":["@c1597"]},{"id":"dai-hon-dao-dan-hon-minh","name":"Đại Hồn đạo — Dẫn Hồn Minh","cn":"大魂道·引魂冥","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Đại Hồn Môn","soHuu":["Phàn San Lộ"],"blurb":"Dẫn Hồn Minh là thần thông thuộc Đại Hồn đạo, cho phép người thi triển tế hiến hồn và phun máu tươi hóa thành thanh trường đao huyết sắc để tấn công. Đao có thể tự phân thành nhiều phần đồng thời đánh trúng nhiều mục tiêu, như khi Phàn San Lộ dùng để đối phó chín hỏa điểu của đạo nhân bảy màu.","detail":"Dẫn Hồn Minh là một thần thông trong hệ thống Đại Hồn đạo. Người thi triển phải phun máu tươi và tế hiến hồn; máu và hồn hợp nhất hóa thành thanh trường đao đỏ như huyết. Thanh đao này có khả năng tự phân thành nhiều phần, mỗi phần giữ nguyên uy lực, cho phép tấn công đồng loạt nhiều mục tiêu cùng lúc. Tại chương @c1598, Phàn San Lộ thi triển Dẫn Hồn Minh khi bị chín hỏa điểu của đạo nhân bảy màu tấn công, đao huyết sắc tự phân chín phần đánh trả chín hỏa điểu cùng lúc. Đại giá của chiêu thức rất lớn, đòi hỏi phải hiến tế cả máu lẫn hồn mới có thể kích phát.","thuocTinh":"Hồn","nguonGoc":"Đại Hồn đạo","uyLuc":"Đao huyết sắc tự phân chín phần đánh chín hỏa điểu của đạo nhân bảy màu cùng lúc @c1598","dacDiem":"Phải phun máu tươi và tế hiến hồn mới thi triển được, đại giá rất lớn cho người sử dụng","congNang":["Tế hiến hồn và phun máu tươi hóa thành thanh trường đao huyết sắc để tấn công @c1598","Đao tự phân thành nhiều phần tấn công đồng thời nhiều mục tiêu, như phân chín phần đánh chín hỏa điểu cùng lúc @c1598"],"nguoiTu":[{"ten":"Phàn San Lộ","tuChuong":"@c1598","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1598","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Phàn San Lộ thi triển khi bị chín hỏa điểu của đạo nhân bảy màu tấn công, tế hiến hồn phun máu hóa thanh trường đao huyết sắc tự phân chín phần chém chín hỏa điểu.","anchor":"Đại Hồn đạo, Dẫn Hồn Minh, tế hiến hồn ta, thành hồn cắt một giới"}]},"nguon":["@c1598"]},{"id":"cam-che-bon-nguyen","name":"Cấm chế bổn nguyên","cn":"","loai":"cong-phap","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"Cấm chế","soHuu":["Vương Lâm"],"blurb":"Cấm chế bổn nguyên là tầng thành tựu mới trong thuật cấm chế, vượt trên tứ đại cấm chế, mà Vương Lâm nhận thấy có khả năng đạt được nếu nắm giữ toàn bộ cấm chế trên chiến thuyền.","detail":"Khi khảo sát chiến thuyền, Vương Lâm nhận diện trên đó có tứ đại cấm chế (Tuế Nguyệt, Sinh Tử, Phá Diệt) cùng nhiều loại cấm chế chưa từng thấy. Ông nhận thấy rằng nếu nắm giữ được toàn bộ các cấm chế này, sẽ có khả năng đạt tới một tầng thành tựu hoàn toàn mới trong thuật cấm chế — gọi là cấm chế bổn nguyên. Đây là cảnh giới đứng trên tứ đại cấm chế, được hé lộ tại thời điểm Vương Lâm nghiên cứu chiến thuyền.","congNang":["Tầng thành tựu mới trong thuật cấm chế, vượt trên tứ đại cấm chế @c1599"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1599","tangDatToi":"Chưa đạt","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1599","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Lần đầu nhận ra khả năng đạt cấm chế bổn nguyên","text":"Vương Lâm khảo sát chiến thuyền, nhận diện tứ đại cấm chế cùng nhiều loại chưa từng thấy, nhận thấy nếu nắm giữ toàn bộ có khả năng đạt thành tựu cấm chế bổn nguyên.","anchor":"nắm giữ toàn bộ cấm chế này thì có khả năng ta sẽ có chút thành tựu cấm chế bổn nguyên"}]},"nguon":["@c1599"]},{"id":"thuat-can-nuot-thien-dao","name":"Thuật cắn nuốt thiên đạo","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thất Thải Thiên Tôn","soHuu":["Thất Thải Thiên Tôn"],"blurb":"Thuật cắn nuốt thiên đạo là thần thông do Thất Thải Thiên Tôn thi triển, triệu hồi thiên đạo từ thế giới động phủ để cắn nuốt đối thủ; đổi lại thiên đạo bị tiêu hao và chết.","detail":"Trong trận đại chiến với Liên Đạo Phi, Thất Thải Thiên Tôn mang thương tích nặng, không đủ sức đối kháng trực tiếp, bèn triệu hồi thiên đạo trong thế giới động phủ thi triển thuật cắn nuốt thiên đạo. Thiên đạo được triệu hồi lao vào cắn nuốt Liên Đạo Phi, khiến đối phương bị trọng thương. Tuy nhiên, cái giá phải trả là thiên đạo của thế giới động phủ cũng chết theo, máu thiên đạo tán lạc, trong khi chúng sinh bên trong động phủ hoàn toàn không hay biết thiên đạo đã diệt vong.","congNang":["Triệu hồi thiên đạo từ thế giới động phủ để cắn nuốt đối thủ, gây trọng thương cho mục tiêu @c1600"],"nguoiTu":[{"ten":"Thất Thải Thiên Tôn","tuChuong":"@c1600","tangDatToi":"","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1600","loai":"thi triển","importance":"major","giaiDoan":"Dùng trong đại chiến với Liên Đạo Phi","text":"Thất Thải Thiên Tôn triệu hồi thiên đạo dùng thuật cắn nuốt thiên đạo đối kháng Liên Đạo Phi, Liên Đạo Phi bị nuốt trọng thương, thiên đạo cũng chết.","anchor":"dùng thuật cắn nuốt thiên đạo để đối kháng với Liên Đạo Phi"}]},"nguon":["@c1600"],"uyLuc":"Khiến Liên Đạo Phi bị thiên đạo nuốt trọng thương, nhưng thiên đạo cũng chết theo, máu thiên đạo tán lạc."},{"id":"than-thong-thon-phe-hon","name":"Thần thông thôn phệ hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Thần thông mà nữ tử áo trắng đề nghị dạy Vương Lâm, dùng để thôn phệ hồn thứ ba của Thất Thải Thiên Tôn.","detail":"Nữ tử áo trắng đề xuất dạy Vương Lâm thần thông này: nếu tìm được hồn thứ ba có thể lợi dụng thần thông mà thôn phệ, biến Vương Lâm thành hồn thứ ba mới, từ đó dung hợp nuốt đạo nhân bảy màu và hồn thứ hai cùng thất phách để trở thành Thất Thải Thiên Tôn hoàn chỉnh. Chưa được truyền dạy thực tế.","congNang":["Thôn phệ một hồn trong tam hồn Thất Thải Thiên Tôn, biến người dùng thành hồn mới"],"tabs":{"tienTrinh":[{"chuong":"@c1600","loai":"xuất hiện","importance":"normal","giaiDoan":"Nữ tử đề xuất dạy Vương Lâm","text":"Nữ tử áo trắng đề nghị dạy Vương Lâm thần thông thôn phệ hồn thứ ba để trở thành Thất Thải Thiên Tôn mới.","anchor":"Ta dạy ngươi một thần thông, ngươi nếu tìm được hồn thứ ba có thể lợi dụng thần thông này mà thôn phệ"}]},"nguon":["@c1600"]},{"id":"chuyen-the-luan-hoi","name":"Phương pháp chuyển thế luân hồi","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Phương pháp mang hồn phách vào Tiên Cương đại lục đầu thai, cách duy nhất để người trong động phủ rời đi mà không chịu kiếp nạn nhập giới.","detail":"Nữ tử áo trắng đề cập: người trong động phủ không chịu nổi kiếp nạn khi ra ngoài, nhưng có thể dùng phương pháp chuyển thế luân hồi mang hồn phách vào Tiên Cương đại lục đầu thai. Nàng hứa giúp người thân Vương Lâm thực hiện điều này nếu hợp tác.","congNang":["Cho phép hồn phách luân hồi đầu thai vào thế giới bên ngoài (Tiên Cương đại lục)"],"tabs":{"tienTrinh":[{"chuong":"@c1600","loai":"nhắc tới","importance":"normal","giaiDoan":"Nữ tử đề cập như điều kiện hợp tác","text":"Nữ tử đề nghị giúp người thân Vương Lâm dùng chuyển thế luân hồi mang hồn phách vào Tiên Cương đại lục đầu thai.","anchor":"lấy phương pháp chuyển thế luân hồi cho người thân ngươi mang hồn phách của họ vào Tiên Cương đại lục đầu thai"}]},"nguon":["@c1600"]},{"id":"luc-luong-dao-co","name":"Lực lượng Đạo cổ","cn":"道古力量","aliases":["Hư ảnh Đạo cổ"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Tam tộc cổ (Cổ Thần + Cổ Yêu + Cổ Ma)","soHuu":["Vương Lâm"],"blurb":"Lực lượng Đạo cổ là thần thông do Vương Lâm tự dung hợp lực lượng tam tộc cổ — Cổ Thần, Cổ Yêu, Cổ Ma — thành một luồng sức mạnh thống nhất, hóa hư ảnh khổng lồ mấy chục trượng bao bọc toàn thân. Đây là phép dung hợp độc đáo kích hoạt từ tinh điểm Cổ Thần trên mi tâm cùng sáu tinh điểm Cổ Yêu trong mắt trái, tạo nên lớp bảo hộ phòng thủ toàn diện.","detail":"Vương Lâm kích hoạt tinh điểm Cổ Thần nằm tại mi tâm cùng sáu tinh điểm Cổ Yêu ẩn trong mắt trái, dung hợp lực lượng ba nhánh Cổ Thần, Cổ Yêu và Cổ Ma thành một dạng lực lượng được gọi là Đạo cổ. Khi hình thành, lực lượng Đạo cổ hóa thành hư ảnh kích thước mấy chục trượng bao bọc quanh toàn thân, có thể chủ động điều chỉnh kích cỡ tùy nhu cầu. Thần thông này không xuất phát từ công pháp truyền thừa mà do chính Vương Lâm tự mình dung hợp nên, thể hiện khả năng hợp nhất sức mạnh đa nguồn gốc của hắn.","congNang":["Dung hợp lực lượng tam tộc cổ (Cổ Thần, Cổ Yêu, Cổ Ma) thành một luồng lực lượng thống nhất @c1601","Hóa hư ảnh Đạo cổ mấy chục trượng bao bọc toàn thân @c1601","Bảo hộ phòng thủ toàn diện @c1601","Có thể điều chỉnh kích cỡ hư ảnh @c1601"],"thuocTinh":"Đạo cổ (tam tộc cổ dung hợp)","nguonGoc":"Vương Lâm tự dung hợp lực lượng ba nhánh Cổ Thần, Cổ Yêu, Cổ Ma","dacDiem":"Kích thước hư ảnh mấy chục trượng, có thể chủ động điều chỉnh kích cỡ; là kết quả dung hợp từ ba nguồn lực lượng cổ đại khác biệt thông qua các tinh điểm trên cơ thể Vương Lâm.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1601","tangDatToi":"Không rõ","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1601","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu triển khai","text":"Vương Lâm dung hợp tinh điểm Cổ Thần mi tâm và sáu tinh điểm Cổ Yêu mắt trái, hóa hư ảnh Đạo cổ mấy chục trượng bao bọc toàn thân để bảo vệ khi nghiên cứu cấm chế trên thuyền.","anchor":"lực lượng tam tộc cổ đồng thời vận chuyển, dung hợp làm một hóa thành một luồng lực lượng của đạo cổ"}]},"nguon":["@c1601"]},{"id":"phap-thuat-ky-di-con-roi","name":"Pháp thuật kỳ dị (con rối)","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Sư tôn Phàn San Mộng","soHuu":["Phàn San Mộng"],"blurb":"Pháp thuật kỳ dị do sư tôn của Phàn San Mộng truyền thụ, cần thệ huyết của mục tiêu làm dẫn chất, có thể biến đối phương thành con rối bị khống chế hoàn toàn.","detail":"Tại chương @c1601, qua nội tâm của Phàn San Mộng, pháp thuật này lần đầu được hé lộ. Nàng cần lấy được thệ huyết của Vương Lâm để dẫn động pháp thuật kỳ dị nhận từ sư tôn (vị sư tôn này chưa lộ diện), từ đó biến Vương Lâm thành con rối nằm dưới sự khống chế của mình. Mục đích cuối cùng của Phàn San Mộng là lợi dụng Vương Lâm sau khi đã bị biến thành con rối để giết Thất Thải Tiên Tôn. Pháp thuật này đòi hỏi điều kiện tiên quyết rõ ràng — thệ huyết của mục tiêu — nên không thể tùy ý thi triển lên bất kỳ ai.","congNang":["Khống chế đối phương thành con rối bị điều khiển, yêu cầu thệ huyết của mục tiêu làm dẫn chất @c1601"],"nguonGoc":"Nhận từ sư tôn của Phàn San Mộng (chưa lộ diện)","nguoiTu":[{"ten":"Phàn San Mộng","tuChuong":"@c1601","tangDatToi":"Không rõ","trangThai":"chua-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1601","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Lộ trong nội tâm Phàn San Mộng","text":"Nội tâm Phàn San Mộng tiết lộ: cần thệ huyết Vương Lâm để dẫn động pháp thuật kỳ dị từ sư tôn, biến Vương Lâm thành con rối nhằm giết Thất Thải Tiên Tôn.","anchor":"Pháp thuật này nàng có thể khiến cho Vương Lâm thành một con rối"}]},"nguon":["@c1601"]},{"id":"huyen-gioi-phan-san-lo","name":"Huyễn giới của Phàn San Lộ","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Phàn San Lộ"],"blurb":"Huyễn thuật của Phàn San Lộ có khả năng tạo huyễn cảnh cực kỳ chân thực, bao trùm không gian rộng lớn trên con thuyền cấm chế, đánh lừa được cả tu sĩ Bước thứ ba Không Linh trung kỳ trong một thời gian. Vương Lâm thừa nhận cả đời chưa từng gặp huyễn giới nào chân thật tới mức này.","detail":"Phàn San Lộ thi triển huyễn giới bao trùm toàn bộ từ tầng hai đến tầng bốn trên con thuyền cấm chế, bao gồm cả hình ảnh đạo nhân bảy màu xuất hiện trên thuyền — tất cả đều là hư ảo do huyễn thuật tạo ra. Huyễn cảnh chân thực đến mức che giấu hoàn toàn ranh giới giữa thật và giả, khiến Vương Lâm phải tuyên bố rằng cả đời chưa từng gặp huyễn giới nào chân thật tới mức này. Cuối cùng, Vương Lâm nhận diện và vạch trần toàn bộ cảnh tượng từ tầng hai đến tầng bốn cùng đạo nhân bảy màu đều là sản phẩm của huyễn giới này (@c1603).","congNang":["Tạo huyễn cảnh cực kỳ chân thực bao trùm không gian rộng lớn (từ tầng hai đến tầng bốn trên thuyền cấm chế), che giấu ranh giới thật-giả @c1603","Phóng chiếu hình ảnh giả (đạo nhân bảy màu) đủ sức đánh lừa người quan sát @c1603"],"uyLuc":"Đánh lừa được tu sĩ Bước thứ ba Không Linh trung kỳ trong một thời gian; Vương Lâm thừa nhận cả đời chưa từng gặp huyễn giới nào chân thật tới mức này.","tabs":{"tienTrinh":[{"chuong":"@c1603","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Bị Vương Lâm vạch trần","text":"Vương Lâm tuyên bố toàn bộ cảnh tượng từ tầng hai đến tầng bốn trên thuyền và đạo nhân bảy màu trên thuyền đều là huyễn giới do Phàn San Lộ tạo ra, chân thật đến mức chưa từng gặp.","anchor":"Cả đời này Vương Lâm ta chưa từng gặp qua một huyễn giới nào chân thật tới mức này"}]},"nguon":["@c1603"]},{"id":"dai-hon-chan-ao-thuat","name":"Đại Hồn chân ảo thuật","cn":"大魂真幻术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Đại Hồn Môn","soHuu":["Phàn San Mộng"],"blurb":"Đại Hồn chân ảo thuật là thần thông ảo thuật cực mạnh xuất phát từ Đại Hồn Môn ở Tiên Cương đại lục, có khả năng biến toàn bộ thực cảnh thành huyễn giới nhiều tầng, che mắt cả đồng minh lẫn kẻ thù. Trong truyện, thuật này được Phàn San Mộng thi triển từ xa để biến toàn bộ cảnh trên thuyền thành huyễn giới.","detail":"Đại Hồn chân ảo thuật là bí thuật trấn phái của Đại Hồn Môn, một thế lực tại Tiên Cương đại lục. Thuật này cho phép người thi triển từ xa, không cần có mặt tại hiện trường, biến toàn bộ thực cảnh thành huyễn giới đa tầng, trong đó cả nhân vật lẫn chiến đấu đều bị huyễn hóa, khiến người trong cuộc không phân biệt được thực — hư. Huyễn cảnh có thể đạt tới song trùng (huyễn trong huyễn), và nếu đạt tam trùng thì không ai có thể thoát ra được. Không phải ai cũng tu luyện được thuật này, đòi hỏi thiên phú đặc biệt. Điểm yếu trọng yếu là nếu huyễn giới bị phá giải, chủ nhân sẽ bị phản phệ, phun máu chịu thương tổn ngược.","thuocTinh":"Ảo thuật","nguonGoc":"Đại Hồn Môn, Tiên Cương đại lục","dacDiem":"Thi triển từ xa không cần ở hiện trường; huyễn cảnh có thể đạt song trùng, tam trùng thì không ai thoát được; đòi hỏi thiên phú đặc biệt mới tu luyện được; nếu bị phá giải, chủ nhân bị phản phệ phun máu chịu thương tổn ngược.","congNang":["Biến toàn bộ thực cảnh thành huyễn giới nhiều tầng, che mắt cả đồng minh lẫn kẻ thù @c1604","Huyễn hóa nhân vật và chiến đấu trong huyễn giới, khiến người trong cuộc không phân biệt thực hư @c1604","Thi triển từ xa, chủ nhân không cần có mặt tại hiện trường @c1604"],"cacTang":[{"ten":"Huyễn cảnh song trọng","moTa":"Huyễn trong huyễn, hai tầng ảo giác chồng lên nhau","chuong":"@c1604"},{"ten":"Huyễn cảnh tam trọng","moTa":"Tầng thứ ba, nếu đạt thì không ai thoát ra được (chưa đạt)","chuong":"@c1604"}],"nguoiTu":[{"ten":"Phàn San Mộng","tuChuong":"@c1604","tangDatToi":"Huyễn cảnh song trọng","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1604","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu lộ diện","text":"Phàn San Mộng từ xa thi triển Đại Hồn chân ảo thuật biến toàn bộ cảnh trên thuyền thành huyễn giới, huyễn hóa đạo nhân bảy màu tấn công, che mắt cả Phàn San Lộ lẫn Vương Lâm. Bị Vương Lâm phá giải, phản phệ phun máu.","anchor":"Đại hồn chân ảo thuật! Đây là thần thông cực mạnh của tỷ tỷ ta!"}]},"nguon":["@c1604"]},{"id":"thuat-thon-hon-nguoi-thu-ba","name":"Thuật thôn hồn người thứ ba","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Đại Hồn Môn","soHuu":["Vương Lâm","Phàn San Lộ"],"blurb":"Thuật thần thông do Phàn San Lộ trao cho Vương Lâm qua ngọc giản, dùng để thôn hồn của người thứ ba.","detail":"Nằm trong ngọc giản cùng bản đồ tế đàn, là thuật mà Phàn San Lộ đã đề cập trước đó trong huyễn giới. Tác dụng chính là thôn hồn người thứ ba, liên quan trực tiếp tới mục tiêu tìm kiếm hồn thứ ba trong đại chiến viễn cổ tiên vực.","congNang":["Thôn hồn của người thứ ba"],"nguon":["@c1605"],"tabs":{"tienTrinh":[{"chuong":"@c1605","loai":"xuất hiện","importance":"normal","giaiDoan":"Phàn San Lộ trao cho Vương Lâm","text":"Phàn San Lộ trao ngọc giản chứa thuật thôn hồn người thứ ba cho Vương Lâm, chính là thuật nàng đã đề cập trong huyễn giới trước đó.","anchor":"thuật mà lúc trước trong huyễn giới ta đã nói - Thuật có thể thôn hồn của người thứ ba"}]}},{"id":"sinh-tu-bon-nguyen","name":"Sinh Tử bổn nguyên","cn":"生死本源","loai":"than-thong","loaiLabel":"Bổn nguyên","phamCap":"Không rõ","hePhai":"Lục đại bổn nguyên","soHuu":["Vương Lâm"],"blurb":"Một trong lục đại bổn nguyên, phóng ra từ mi tâm cùng Nhân Quả và Chân Giả bổn nguyên, dung nhập vào dòng xoáy tạo thành chiếc loa phóng đại âm thanh.","detail":"Sinh Tử bổn nguyên là một trong sáu bổn nguyên mà Vương Lâm nắm giữ. Được phóng ra từ mi tâm cùng lúc với Nhân Quả bổn nguyên và Chân Giả bổn nguyên, dung nhập vào dòng xoáy do lôi hỏa bổn nguyên khởi tạo, góp phần ngưng tụ thành chiếc loa lục đại bổn nguyên phóng đại âm thanh.","nguon":["@c1607"]},{"id":"nhan-qua-bon-nguyen","name":"Nhân Quả bổn nguyên","cn":"因果本源","loai":"than-thong","loaiLabel":"Bổn nguyên","phamCap":"Không rõ","hePhai":"Lục đại bổn nguyên","soHuu":["Vương Lâm"],"blurb":"Một trong lục đại bổn nguyên, phóng ra từ mi tâm cùng Sinh Tử và Chân Giả bổn nguyên, thành phần tạo loa bổn nguyên.","detail":"Nhân Quả bổn nguyên là một trong sáu bổn nguyên Vương Lâm sở hữu. Được phóng ra từ mi tâm đồng thời với Sinh Tử bổn nguyên và Chân Giả bổn nguyên, dung nhập vào dòng xoáy bổn nguyên tạo thành chiếc loa phóng đại âm thanh.","nguon":["@c1607"]},{"id":"tieng-rong-dao-co","name":"Tiếng rống Đạo cổ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Đạo cổ","soHuu":["Vương Lâm"],"blurb":"Tiếng rống Đạo cổ là thần thông Vương Lâm lĩnh ngộ khi đẩy lui Chưởng Tôn ở vùng đất cổ mộ, mang trong mình lực lượng của Đạo cổ dung hợp tam tộc cổ. Lần đầu thi triển toàn lực qua chiếc loa do lục đại bổn nguyên ngưng tụ, uy lực đủ sụp đổ thiên không, nứt vỡ đại địa.","detail":"Tiếng rống Đạo cổ là thần thông Vương Lâm lĩnh ngộ trong trận đẩy lui Chưởng Tôn ở vùng đất cổ mộ. Thần thông này vận dụng Đạo cổ lực — sức mạnh dung hợp của tam tộc cổ — phát ra tiếng rống mang bản chất của Cổ Thần, của Đạo cổ. Khi phối hợp với chiếc loa do lục đại bổn nguyên ngưng tụ, âm thanh được phóng đại vô số lần, uy lực kinh thiên động địa. Lần thi triển toàn lực đầu tiên được ghi nhận tại chương 1607, tiếng rống khiến thiên không sụp đổ, đại địa run rẩy nứt vỡ, phong vân biến sắc.","congNang":["Phát ra tiếng rống Đạo cổ mang lực lượng của Cổ Thần, dung hợp tam tộc cổ @c1607","Phóng đại uy lực qua chiếc loa do lục đại bổn nguyên ngưng tụ, khuếch đại âm thanh vô số lần @c1607","Uy lực đủ làm sụp đổ thiên không, đại địa run rẩy nứt vỡ, phong vân biến sắc @c1607"],"nguonGoc":"Học từ trận đẩy lui Chưởng Tôn ở vùng đất cổ mộ","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1607","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1607","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển toàn lực","text":"Vương Lâm lần đầu thi triển toàn lực thần thông tiếng rống Đạo cổ qua chiếc loa lục đại bổn nguyên ngưng tụ, kết hợp Đạo cổ lực dung hợp tam tộc cổ, khiến thiên không sụp đổ, đại địa nứt vỡ, phong vân biến sắc.","anchor":"Một tiếng rống này là tiếng rống của Cổ Thần, là tiếng rống của Đạo cổ, cũng là thần thông khi ở vùng đất cổ mộ Vương Lâm đẩy lui Chưởng Tôn mà học được"}]},"nguon":["@c1607"],"uyLuc":"Thi triển toàn lực qua loa lục đại bổn nguyên, tiếng rống khiến thiên không sụp đổ, đại địa run rẩy nứt vỡ, phong vân biến sắc.","dacDiem":"Là tiếng rống của Cổ Thần, của Đạo cổ, vận dụng Đạo cổ lực dung hợp tam tộc cổ; có thể kết hợp với loa lục đại bổn nguyên để phóng đại uy lực vô số lần."},{"id":"loa-luc-dai-bon-nguyen","name":"Loa lục đại bổn nguyên","cn":"","loai":"bi-thuat","loaiLabel":"Pháp khí tạm thời","phamCap":"Không rõ","hePhai":"Lục đại bổn nguyên","soHuu":["Vương Lâm"],"blurb":"Chiếc loa do Vương Lâm dùng lục đại bổn nguyên ngưng tụ thành, bên trong có nhiều tầng tăng âm, phóng đại âm thanh vô số lần.","detail":"Vương Lâm dùng lục đại bổn nguyên (lôi hỏa, Sinh Tử, Nhân Quả, Chân Giả, sát lục) ngưng tụ thành hình chiếc loa phóng đại âm thanh. Lôi hỏa bổn nguyên từ mắt trái mắt phải tạo dòng xoáy, ba bổn nguyên Sinh Tử, Nhân Quả, Chân Giả từ mi tâm dung nhập, cuối cùng sát lục bổn nguyên gia nhập hoàn thiện. Bên trong chiếc loa có nhiều tầng do khí tức bổn nguyên chuyển động tạo thành, phóng đại âm thanh vô số lần.","congNang":["Phóng đại âm thanh vô số lần, dùng khuếch đại tiếng rống Đạo cổ @c1607"],"nguon":["@c1607"]},{"id":"tran-phap-tang-thuong-te-dan","name":"Trận pháp tang thương trên tế đàn","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Trận pháp trên đỉnh tế đàn bát giác trong khe Vân Hải tinh vực, hợp thành từ vô số ký hiệu màu đen, trung tâm đặt cánh tay mười trượng tỏa khí tức Đạo Cổ.","detail":"Nằm trên đỉnh tế đàn rộng trăm trượng. Vô số ký hiệu màu đen hợp thành trận pháp mang hình thái tang thương. Trung tâm trận pháp chính là trung tâm tế đàn, nơi đặt một cánh tay kích thước mười trượng tỏa khí tức Đạo Cổ.","nguon":["@c1608"],"tabs":{"tienTrinh":[{"chuong":"@c1608","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu miêu tả","text":"Trận pháp tang thương trên đỉnh tế đàn bát giác được hé lộ khi Vương Lâm hướng tới tế đàn tìm sinh cơ.","anchor":"trên đó có vô số ký hiệu màu đen hợp thành một trận pháp tang thương"}]}},{"id":"hu-anh-dao-co","name":"Hư ảnh Đạo cổ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Đạo cổ","soHuu":["Vương Lâm"],"blurb":"Thần thông dung hợp lực lượng tam tộc cổ (Cổ Thần, Cổ Yêu, Cổ quốc) hóa thành hư ảnh Đạo cổ lớn mấy chục trượng bao bọc bảo vệ toàn thân.","detail":"Vương Lâm vận chuyển tinh điểm Cổ Thần trên mi tâm cùng sáu tinh điểm Cổ Yêu trong mắt trái, dung hợp lực lượng ba tộc cổ thành một luồng lực lượng Đạo cổ, hóa thành hư ảnh khổng lồ bao bọc toàn thân. Dùng để phòng hộ khi nghiên cứu cấm chế trên thuyền Đại Hồn Môn.","thuocTinh":"Đạo cổ (tam tộc cổ dung hợp)","nguonGoc":"Vương Lâm tự dung hợp lực lượng tam tộc cổ","congNang":["Phòng hộ toàn thân bằng hư ảnh Đạo cổ lớn mấy chục trượng"],"dacDiem":"Cần đồng thời vận chuyển tinh điểm Cổ Thần và tinh điểm Cổ Yêu, dung hợp làm một","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1601","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1601","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm dung hợp lực lượng tam tộc cổ hóa hư ảnh Đạo cổ bảo vệ toàn thân khi nghiên cứu cấm chế trên thuyền Đại Hồn Môn.","anchor":"lực lượng tam tộc cổ đồng thời vận chuyển, dung hợp làm một hóa thành một luồng lực lượng của đạo cổ"}]},"nguon":["@c1601"]},{"id":"phap-thuat-ky-di-su-ton-phan-san-mong","name":"Pháp thuật kỳ dị (sư tôn Phàn San Mộng)","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Phàn San Mộng"],"blurb":"Pháp thuật của sư tôn Phàn San Mộng, cần thệ huyết của đối tượng để dẫn động, có thể biến người thành con rối.","detail":"Phàn San Mộng dự định dùng thệ huyết của Vương Lâm để nhận trợ giúp từ sư tôn, dẫn động pháp thuật kỳ dị này biến Vương Lâm thành con rối, phục vụ mục đích giết Thất Thải Tiên Tôn.","congNang":["Biến người thành con rối thông qua thệ huyết"],"dacDiem":"Cần thệ huyết của đối phương làm chất dẫn, cần sự trợ giúp của sư tôn","nguoiTu":[{"ten":"Phàn San Mộng","tuChuong":"@c1601","tangDatToi":"","trangThai":"chua-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1601","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Lộ mục đích trong nội tâm Phàn San Mộng","text":"Phàn San Mộng nội tâm bật mí dự định dùng thệ huyết Vương Lâm dẫn động pháp thuật biến hắn thành con rối để giết Thất Thải Tiên Tôn.","anchor":"Dùng thệ huyết này nàng có thể nhận được sự trợ giúp của sư tôn, dẫn động một pháp thuật kỳ dị"}]},"nguon":["@c1601"]},{"id":"tam-toc-co-dong-tu","name":"Tam tộc cổ đồng tu","loai":"cong-phap","loaiLabel":"Công pháp","soHuu":["Vương Lâm"],"blurb":"Tam tộc cổ đồng tu là phương pháp tu luyện đồng thời ba hệ Cổ Thần, Cổ Yêu, Cổ Ma, dùng khí tức Đạo cổ nuôi dưỡng đồng đều ba loại tinh điểm thay vì chỉ tăng đơn thuần một hệ. Vương Lâm áp dụng pháp này khi hấp thu máu Đạo cổ của Diệp Mịch, đột phá từ Thất Tinh lên Bát Tinh cả ba hệ đồng thời.","detail":"Vương Lâm hấp thu tám giọt máu Đạo cổ của Diệp Mịch qua thất khiếu và lỗ chân lông, sau đó phân chia khí tức Đạo cổ đồng thời nuôi dưỡng Cổ Thần tinh, yêu tinh và ma tinh, khiến lực lượng tam tộc cổ cùng tăng trưởng thăng bằng. Nhờ cách tu luyện này, cả ba hệ cùng đột phá lên Bát Tinh trong một lần, thay vì phải nâng cấp riêng lẻ từng hệ.","congNang":["Phân khí tức Đạo cổ đồng thời nuôi dưỡng Cổ Thần tinh, yêu tinh, ma tinh, khiến tam tộc cổ cùng tăng trưởng thăng bằng @c1610","Cho phép đột phá đồng thời cả ba hệ Cổ Thần, Cổ Yêu, Cổ Ma trong cùng một lần @c1610"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1610","tangDatToi":"Bát Tinh","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1610","loai":"thi triển","importance":"major","giaiDoan":"Thất Tinh lên Bát Tinh","text":"Vương Lâm hấp thu tám giọt máu Đạo cổ Diệp Mịch, phân khí tức nuôi đồng đều ba hệ, đột phá Bát Tinh tam tộc cổ đồng thời.","anchor":"Hắn muốn lực lượng của tam tộc cổ cùng tăng lên thăng bằng"}]},"nguon":["@c1610"],"uyLuc":"Hấp thu tám giọt máu Đạo cổ của Diệp Mịch, đột phá trực tiếp từ Thất Tinh lên Bát Tinh cả ba hệ đồng thời @c1610","dacDiem":"Tu luyện ba hệ cổ tộc song song bằng cách phân chia một nguồn khí tức Đạo cổ duy nhất, duy trì sự thăng bằng giữa Cổ Thần, Cổ Yêu và Cổ Ma thay vì thiên lệch một hệ"},{"id":"co-mach-thuong-khung-huyet","name":"Cổ Mạch Thương Khung Huyết","cn":"古脉苍穹血","loai":"khac","loaiLabel":"Kiếp nạn (đệ tam tổn đệ nhất kiếp)","phamCap":"Không rõ","hePhai":"Đạo Cổ","soHuu":["Vương Lâm"],"blurb":"Cổ Mạch Thương Khung Huyết là kiếp thứ nhất của đệ tam tổn, yêu cầu ngưng tụ tinh khí thần của cả ba tộc Cổ Thần, Cổ Yêu, Cổ Ma thành một giọt máu tươi duy nhất, dùng giọt máu đó phá tan trời cao gọi huyết mạch cổ quốc. Nếu được cổ tổ chấp thuận ban máu, người tu luyện sẽ tái sinh thân thể, đạt huyết mạch cổ chính thức ngang cấp huyết mạch tiên nhân.","detail":"Cổ Mạch Thương Khung Huyết đòi hỏi người tu phải sở hữu bản nguyên của cả ba tộc cổ — Cổ Thần, Cổ Ma, Cổ Yêu — rồi lần lượt hòa tan ba thân thể thành ba giọt máu riêng biệt, sau đó dung hợp ba giọt thành một giọt máu tươi duy nhất. Quá trình ngưng tụ kéo dài mười ba ngày. Giọt máu dung hợp được dùng để phá tan trời cao, phát đi tín hiệu gọi về huyết mạch cổ quốc; khí tức cổ tổ lan tỏa khiến mọi cổ tộc chấn động. Nếu cổ tổ chấp thuận, sẽ ban máu tươi giao hòa với tinh khí thần người tu, tái sinh toàn bộ thân thể, đạt huyết mạch cổ chính thức ngang cấp với huyết mạch tiên nhân. Số giọt máu cổ tổ ban tặng khác nhau tùy mức chấp thuận: Đạo Cổ Diệp Mịch được ba giọt, kỷ lục cao nhất là tám giọt thuộc về Huyền La Đại Thiên Tôn. Trên pho tượng cổ tổ, số giọt máu hiện ra phản ánh thành tựu của ngư","congNang":["Ngưng tụ tinh khí thần của ba tộc Cổ Thần, Cổ Ma, Cổ Yêu, hòa tan ba thân thể thành ba giọt máu rồi dung hợp thành một giọt máu tươi duy nhất @c1612","Dùng giọt máu dung hợp phá tan trời cao, gọi về huyết mạch cổ quốc @c1611","Phát tín hiệu cổ tổ: khí tức lan tỏa khiến mọi cổ tộc chấn động @c1612","Được cổ tổ ban máu tươi, giao hòa với tinh khí thần để tái sinh toàn bộ thân thể","Đạt huyết mạch cổ chính thức ngang cấp huyết mạch tiên nhân","Số giọt máu trên pho tượng cổ tổ phản ánh thành tựu của người ngưng tụ @c1612"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1611","tangDatToi":"Đang tiến hành, bốn giọt máu","trangThai":"dang-tu"},{"ten":"Đạo Cổ Diệp Mịch","tuChuong":"@c1611","tangDatToi":"Hoàn thành (3 giọt)","trangThai":"hoan-thanh"},{"ten":"Huyền La Đại Thiên Tôn","tuChuong":"@c1611","tangDatToi":"Đã thành (năm xưa mất chín ngày)","trangThai":"da-thanh"}],"tabs":{"tienTrinh":[{"chuong":"@c1611","loai":"xuất hiện","importance":"major","giaiDoan":"Hé lộ nội dung kiếp và Vương Lâm bắt đầu tiến hành","text":"Hé lộ nội dung kiếp Cổ Mạch Thương Khung Huyết: ngưng tụ giọt máu phá trời gọi huyết mạch cổ tổ. Vương Lâm bắt đầu hòa tan tinh khí thần thành giọt máu, phân thân tu sĩ tách khỏi bổn tôn.","anchor":"Dùng giọt máu tươi này có thể phá tan cả trời cao gọi về huyết mạch của cổ quốc"},{"chuong":"@c1612","loai":"thi triển","importance":"major","giaiDoan":"Vương Lâm ngưng tụ cổ Mạch Thương Khung Huyết — bốn giọt máu","text":"Vương Lâm hòa tan lần lượt ba thân thể thành ba giọt máu rồi dung hợp thành một. Quá trình mười ba ngày, trên mi tâm pho tượng cổ tổ hiện bốn giọt máu gây kinh ngạc toàn cổ quốc. Huyền La năm xưa chỉ mất chín ngày.","anchor":"Lấy thân thể Cổ Yêu của ta, dung hợp tinh khí thần thành một giọt máu tươi"}]},"nguon":["@c1611","@c1612"],"dacDiem":"Quá trình ngưng tụ kéo dài mười ba ngày, yêu cầu bản nguyên đầy đủ của cả ba tộc cổ; số giọt máu cổ tổ ban tặng tùy mức chấp thuận, kỷ lục cao nhất là tám giọt của Huyền La Đại Thiên Tôn."},{"id":"co-dao-tam-phan-than","name":"Cổ Đạo Tam Phân Thần","cn":"古道三分神","loai":"khac","loaiLabel":"Kiếp nạn (đệ tam tổn đệ nhị kiếp)","phamCap":"Không rõ","hePhai":"Đạo Cổ","soHuu":[],"blurb":"Kiếp thứ hai của đệ tam tổn, chưa mô tả chi tiết.","detail":"Tên kiếp thứ hai của đệ tam tổn trong hệ thống tam tổn thất kiếp. Nội dung cụ thể chưa được hé lộ.","tabs":{"tienTrinh":[{"chuong":"@c1611","loai":"nhắc tới","importance":"bridge","giaiDoan":"Nhắc tên kiếp","text":"Được nhắc tên là kiếp thứ hai của đệ tam tổn, chưa mô tả chi tiết.","anchor":"Đệ nhị là cổ Đạo Tam Phân Thần!"}]},"nguon":["@c1611"]},{"id":"co-to-chi-tu","name":"Cổ Tổ Chi Tứ","cn":"古祖之赐","loai":"khac","loaiLabel":"Kiếp nạn (đệ tam tổn đệ tam kiếp)","phamCap":"Không rõ","hePhai":"Đạo Cổ","soHuu":[],"blurb":"Kiếp cuối cùng, cường đại nhất cổ quốc. Nghĩa là ban thưởng của cổ tổ. Vượt qua là đại sự cả cổ quốc, gọi là kỳ điển.","detail":"Kiếp cuối cùng và cường đại nhất của hệ thống tam tổn thất kiếp. Nghĩa là ban thưởng của cổ tổ. Hễ cư dân cổ quốc tu luyện tới kiếp này thì đều là đại sự cả nước, được gọi là kỳ điển. Tiên tộc cũng cực kỳ coi trọng. Đạo Cổ Diệp Mịch năm đó vượt kiếp này tại cổ miếu, dung hợp danh hiệu tam tộc thành đại tôn.","tabs":{"tienTrinh":[{"chuong":"@c1611","loai":"nhắc tới","importance":"normal","giaiDoan":"Hé lộ ý nghĩa kiếp cuối","text":"Được giới thiệu là kiếp cuối cùng, cường đại nhất, vượt qua là đại sự cả cổ quốc gọi là kỳ điển. Đạo Cổ Diệp Mịch từng vượt kiếp này tại cổ miếu.","anchor":"Hễ là cư dân của cổ quốc, nếu có thể tu luyện tới kiếp cuối cùng thì đều là đại sự của cả cổ quốc"}]},"nguon":["@c1611"]},{"id":"huyen-duong","name":"Huyền Dương","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Đạo cổ nhất mạch","soHuu":["Huyền La Đại Thiên Tôn"],"blurb":"Huyền Dương là lực lượng đặc hữu của Huyền La Đại Thiên Tôn, có thể triệu ra mặt trời khổng lồ màu đỏ phong bế toàn bộ thiên địa một khu vực, che giấu khí tức và sự kiện bên trong.","detail":"Huyền La Đại Thiên Tôn thi triển lực lượng Huyền Dương tại thành trì Đạo cổ nhất mạch, triệu ra một mặt trời khổng lồ màu đỏ phong bế thiên địa toàn khu vực, nhằm che giấu sự kiện liên quan đến hồn huyết cổ tổ. Uy lực của Huyền Dương bao phủ phạm vi cực rộng, ảnh hưởng tới gần trăm vạn tộc nhân trong vùng.","congNang":["Triệu ra mặt trời khổng lồ màu đỏ phong bế không gian thiên địa toàn khu vực @c1614","Che giấu khí tức và sự kiện bên trong vùng phong bế @c1614"],"nguoiTu":[{"ten":"Huyền La Đại Thiên Tôn","tuChuong":"@c1614","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1614","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu lộ diện","text":"Huyền La Đại Thiên Tôn dùng lực lượng Huyền Dương triệu mặt trời đỏ phong bế thiên địa thành trì Đạo cổ, hạ lệnh phong bế tin tức hồn huyết.","anchor":"Lấy lực lượng Huyền Dương của ta phong bế nơi này"}]},"nguon":["@c1614"],"uyLuc":"Bao phủ toàn bộ khu vực thành trì Đạo cổ, phong bế thiên địa ảnh hưởng tới gần trăm vạn tộc nhân.","dacDiem":"Biểu hiện dưới hình thái mặt trời khổng lồ màu đỏ, là lực lượng đặc hữu chỉ thuộc về Huyền La Đại Thiên Tôn."},{"id":"tam-ton","name":"Tam tổn","cn":"三损","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Truyền thuyết cổ tộc","hePhai":"Đạo cổ nhất mạch","soHuu":["Vương Lâm"],"blurb":"Tam tổn là hệ thống kiếp nạn cổ truyền của Đạo cổ quốc, gồm tam kiếp: đệ nhất kiếp Cổ Mạch Thương Khung Huyết, đệ nhị kiếp Cổ Đạo Tâm Phân Thần, đệ tam kiếp Cổ Tổ Chi Tứ. Trải qua trọn vẹn cả ba kiếp có thể đạt được truyền thừa cổ tổ — thành tựu mà vạn vạn năm chưa ai đạt tới.","detail":"Tam tổn là di pháp do cổ tổ của Đạo cổ quốc truyền lại, bản chất là ba tầng kiếp nạn mà tộc nhân phải vượt qua để đạt truyền thừa tối thượng. Đệ nhất kiếp mang tên Cổ Mạch Thương Khung Huyết, liên quan đến cổ mạch và huyết thống — Vương Lâm đã trải qua kiếp này, đạt được năm giọt máu tươi cùng một giọt hồn huyết màu tím, chính là giọt hồn huyết thứ mười của cổ quốc. Đệ nhị kiếp mang tên Cổ Đạo Tâm Phân Thần, liên quan đến phân hóa đạo tâm và thần thức, vượt qua sẽ đạt thêm cơ duyên. Đệ tam kiếp mang tên Cổ Tổ Chi Tứ, là kiếp nạn cuối cùng, hoàn thành trọn vẹn sẽ nhận được truyền thừa cổ tổ. Tộc nhân Đạo cổ từng bàn luận về tam tổn, cho thấy đây là sự kiện được cả tộc quan tâm sâu sắc @c1615.","thuocTinh":"Cổ tộc huyết mạch","nguonGoc":"Truyền thuyết cổ quốc, cổ tổ truyền lại","cacTang":[{"ten":"Đệ nhất kiếp — Cổ Mạch Thương Khung Huyết","moTa":"Vương Lâm đã trải qua, đạt 5 giọt máu tươi + 1 giọt hồn huyết màu tím","chuong":"@c1615"},{"ten":"Đệ nhị kiếp — Cổ Đạo Tâm Phân Thần","moTa":"Phân hóa, đạt thêm cơ duyên (chưa trải qua)","chuong":"@c1615"},{"ten":"Đệ tam kiếp — Cổ Tổ Chi Tứ","moTa":"Kiếp cuối, có thể đạt truyền thừa cổ tổ vạn vạn năm chưa ai đạt (chưa trải qua)","chuong":"@c1615"}],"congNang":["Trải qua đệ nhất kiếp Cổ Mạch Thương Khung Huyết có thể đạt được hồn huyết và máu tươi cổ quốc — Vương Lâm đạt năm giọt máu tươi cùng một giọt hồn huyết màu tím (giọt thứ mười của cổ quốc)","Trải qua đệ nhị kiếp Cổ Đạo Tâm Phân Thần đạt thêm cơ duyên, liên quan đến phân hóa","Trải qua trọn vẹn tam kiếp có thể đạt truyền thừa cổ tổ, thành tựu vạn vạn năm chưa tộc nhân nào đạt được @c1615"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1615","tangDatToi":"Đệ nhất kiếp hoàn thành","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1615","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Lộ cấu trúc đầy đủ tam kiếp","text":"Tộc nhân Đạo cổ bàn luận: tam tổn có tam kiếp — đệ nhất Cổ Mạch Thương Khung Huyết, đệ nhị Cổ Đạo Tâm Phân Thần, đệ tam Cổ Tổ Chi Tứ. Mỗi kiếp đạt thêm cơ duyên, kiếp cuối có thể đạt truyền thừa cổ tổ vạn vạn năm chưa ai đạt.","anchor":"Tam tổn có tam kiếp, đệ nhất kiếp là cổ Mạch Thương Khung Huyết"}]},"capNhatToi":"@c1615","nguon":["@c1615"]},{"id":"thuat-phong-an-huyen-la","name":"Thuật phong ấn (Huyền La Đại Thiên Tôn)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Đạo cổ nhất mạch","soHuu":["Huyền La Đại Thiên Tôn"],"blurb":"Thần thông phong ấn của Huyền La Đại Thiên Tôn, phân hóa mặt trời đỏ thành gần trăm vạn phần dung nhập vào thân tộc nhân để cấm lan truyền tin tức.","detail":"Phân hóa mặt trời đỏ thành gần trăm vạn phần đồng loạt dung nhập vào thân thể tộc nhân Đạo cổ, hình thành phong ấn cấm lan truyền tin tức. Có khả năng phong ấn ký ức và lời nói của gần trăm vạn người cùng lúc.","congNang":["Phong ấn ký ức và lời nói của gần trăm vạn người cùng lúc"],"tabs":{"tienTrinh":[{"chuong":"@c1615","loai":"thi-trien","importance":"normal","giaiDoan":"Thi triển phong ấn tin tức hồn huyết","text":"Huyền La Đại Thiên Tôn phân hóa mặt trời đỏ dung nhập vào thân gần trăm vạn tộc nhân, phong ấn cấm lan truyền tin tức giọt hồn huyết thứ mười.","anchor":"đồng loạt dung nhập bên trong thân thể tộc nhân của Đạo cổ, hình thành thuật phong ấn"}]},"capNhatToi":"@c1615","nguon":["@c1615"]},{"id":"nghich-thien-khau-quyet-co-to","name":"Nghịch thiên khẩu quyết Cổ Tổ","cn":"逆天口訣","loai":"khac","loaiLabel":"Khẩu quyết / Tư tưởng","phamCap":"Không rõ","hePhai":"Cổ tộc","soHuu":["Cổ Tổ"],"blurb":"Nghịch thiên khẩu quyết là bài khẩu quyết do Cổ Tổ truyền lại cho hậu nhân cổ tộc, tổng kết tư tưởng nghịch tiên cốt lõi: \"Thuận là phàm, nghịch là tiên, nghịch thiên thành tiên, nghịch tiên thành cổ.\" Khẩu quyết đóng vai trò kim chỉ nam tinh thần cho toàn bộ Đạo cổ nhất mạch.","detail":"Cổ Tổ xuất hiện trong giấc mộng của Vương Lâm, tuyên bố ý chí nghịch tiên và truyền khẩu quyết này cho hậu nhân cổ tộc (@c1616). Cổ tộc vốn sinh ra trước thiên địa, nhưng tiên xuất hiện trước và muốn nô dịch cổ tộc, vì vậy cổ tộc thề hủy diệt tiên. Khẩu quyết là sự chắt lọc toàn bộ tư tưởng đó thành bốn câu cương lĩnh, được Cổ Tổ truyền cho ba người con cùng các đời hậu nhân, trở thành nền tảng tinh thần xuyên suốt của Đạo cổ.","thuocTinh":"Nghịch thiên","nguonGoc":"Cổ Tổ truyền cho ba con và hậu nhân cổ tộc","congNang":["Tổng kết tư tưởng nghịch tiên của cổ tộc, đúc thành cương lĩnh tinh thần cho toàn bộ Đạo cổ nhất mạch (@c1616)"],"nguoiTu":[{"ten":"Cổ Tổ","tuChuong":"@c1616","tangDatToi":"","trangThai":"khai-sang"}],"tabs":{"tienTrinh":[{"chuong":"@c1616","loai":"xuất hiện","importance":"major","giaiDoan":"Cổ Tổ truyền trong mộng Vương Lâm","text":"Cổ Tổ xuất hiện trong giấc mộng Vương Lâm, tuyên bố ý chí nghịch tiên và truyền khẩu quyết cho hậu nhân cổ tộc.","anchor":"Thuận là phàm, nghịch là tiên, nghịch thiên thành tiên, nghịch tiên thành cổ"}]},"nguon":["@c1616"]},{"id":"chien-bon-nguyen","name":"Chiến bổn nguyên","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Chưa rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Bổn nguyên từ chiến đạo mà Vương Lâm cảm ngộ năm đó, đã hóa thành tinh điểm quy tắc, cần thời gian điều chỉnh. Nếu sinh bổn nguyên thêm từ đó có thể đạt Không Linh đỉnh phong.","detail":"Vương Lâm từng cảm ngộ chiến bổn nguyên và hóa thành tinh điểm quy tắc. Hiện cần thời gian điều chỉnh, nếu thành công sinh thêm bổn nguyên từ đó sẽ đạt tới Không Linh đỉnh phong.","congNang":["Nếu sinh bổn nguyên thêm → đạt Không Linh đỉnh phong"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1618","tangDatToi":"Chưa thành","trangThai":"đang tu luyện"}],"tabs":{"tienTrinh":[{"chuong":"@c1618","loai":"nhắc tới","importance":"normal","giaiDoan":"Chưa thành","text":"Vương Lâm nhắc tới chiến bổn nguyên đã hóa thành tinh điểm quy tắc, cần thời gian điều chỉnh, nếu sinh bổn nguyên thêm sẽ đạt Không Linh đỉnh phong.","anchor":"Nếu cũng có thể sinh ra bổn nguyên từ đó thì ta có thể đạt tới Không Linh đỉnh phong"}]},"nguon":["@c1618"]},{"id":"huyen-dao-dai-hon-mon","name":"Huyễn đạo (Đại Hồn Môn)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Đại Hồn Môn","soHuu":["Phàn San Mộng"],"blurb":"Thần thông huyễn đạo xuất phát từ Đại Hồn Môn, buồm mặt quỷ có liên quan mật thiết. Vương Lâm nghiên cứu huyễn đạo này để tìm hồn thứ ba.","detail":"Buồm mặt quỷ từng được Phàn San Mộng dùng để thi triển ảo thuật, có liên quan tới thần thông huyễn đạo của Đại Hồn Môn. Vương Lâm xác định nghiên cứu huyễn đạo là trọng điểm để tìm hồn thứ ba, tương tự phương pháp đạo nhân bảy màu.","congNang":["Dùng để thi triển ảo thuật","Trọng điểm tìm hồn thứ ba"],"nguoiTu":[{"ten":"Phàn San Mộng","tuChuong":"@c1618","tangDatToi":"Chưa rõ","trangThai":"chưa rõ"}],"tabs":{"tienTrinh":[{"chuong":"@c1618","loai":"nhắc tới","importance":"normal","giaiDoan":"Vương Lâm xác định nghiên cứu","text":"Vương Lâm xác nhận buồm mặt quỷ liên quan huyễn đạo Đại Hồn Môn, quyết định nghiên cứu để tìm hồn thứ ba.","anchor":"quan trọng nhất là tấm buồm mặt quỷ này có thể được Phàn San Mộng dùng để thi triển ảo thuật, tất nhiên là có liên quan tới thần thông huyễn đạo của Đại Hồn Môn"}]},"nguon":["@c1618"]},{"id":"huyet-cam","name":"Huyết cấm","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Cấm chế","soHuu":["Vương Lâm"],"blurb":"Huyết cấm là kỹ thuật do Vương Lâm tự sáng tạo trong quá trình dung hợp cấm chế bổn nguyên, lấy máu tươi bản thân làm vật dẫn để dung hợp hàng ngàn cấm chế. Tại lần dung hợp thứ chín, Vương Lâm phun máu chia thành 3172 phần, huyết quang chói lóa, cuối cùng hơn ba ngàn cấm chế ngưng kết còn lại chín cấm chế lớn ngàn trượng, tỏa khí tức tang thương.","detail":"Huyết cấm không phải công pháp truyền thừa mà là phương pháp Vương Lâm tự nghĩ ra trong quá trình dung hợp cấm chế bổn nguyên. Nguyên lý cốt lõi là lấy máu tươi của chính bản thân làm vật dẫn: người thi triển vỗ chưởng lên thân mình khiến máu phun ra, rồi phân chia lượng máu ấy thành số phần tương ứng với số cấm chế cần dung hợp, mỗi phần máu đối ứng một cấm chế. Nhờ phương pháp này, Vương Lâm hoàn thành dung hợp cấm chế lần thứ chín, đưa hơn ba ngàn cấm chế ngưng lại chỉ còn chín cấm chế khổng lồ cao ngàn trượng, tỏa ra khí tức tang thương. Quá trình thi triển đi kèm huyết quang chói lóa bao phủ.","nguon":["@c1619"],"thuocTinh":"Huyết","nguonGoc":"Vương Lâm tự nghĩ ra trong quá trình dung hợp cấm chế bổn nguyên","yeuCau":"Cần phun máu tươi bản thân làm vật dẫn","uyLuc":"Dung hợp hơn ba ngàn cấm chế còn lại chín cấm chế lớn ngàn trượng, tỏa khí tức tang thương, huyết quang chói lóa @c1619","dacDiem":"Lấy máu tươi bản thân làm vật dẫn, mỗi phần máu tương ứng một cấm chế; là kỹ thuật Vương Lâm tự sáng tạo chứ không phải công pháp truyền thừa","congNang":["Lấy máu tươi bản thân làm vật dẫn, mỗi phần máu tương ứng một cấm chế, dung hợp hàng ngàn cấm chế cùng lúc @c1619"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1619","tangDatToi":"","trangThai":"thi triển lần đầu"}],"tabs":{"tienTrinh":[{"chuong":"@c1619","loai":"thi triển","importance":"major","giaiDoan":"Thi triển lần đầu","text":"Vương Lâm phun máu tươi chia 3172 phần làm vật dẫn, hoàn thành dung hợp cấm chế lần thứ chín, từ hơn ba ngàn cấm chế còn chín cái lớn ngàn trượng.","anchor":"Huyết cấm, dung hợp lần thứ chín"}]}},{"id":"cam-che-bon-nguyen-dao-bon-nguyen","name":"Cấm chế bổn nguyên","cn":"禁制本源","loai":"than-thong","loaiLabel":"Đạo bổn nguyên","phamCap":"Đạo bổn nguyên thứ bảy (chưa đại thành)","hePhai":"Tự ngộ","soHuu":["Vương Lâm"],"blurb":"Cấm chế bổn nguyên là đạo bổn nguyên thứ bảy của Vương Lâm, lấy tơ máu đồng tử hai mắt làm sợi tơ quy tắc, dung hợp toàn bộ cấm chế xung quanh vào bản thân. Đây là phương pháp từ cổ chí kim chưa ai nghĩ tới, bản chất giống quy tắc thiên địa nhưng thuộc về riêng Vương Lâm.","detail":"Vương Lâm trong quá trình nghiên cứu tấm buồm mặt quỷ và quy tắc thiên địa đã tự ngộ ra bản chất: quy tắc và pháp tắc giống như vô số sợi tơ vô hình cuốn quanh vạn vật, còn cấm chế vốn là sinh linh thượng cổ bắt chước quy tắc thiên địa mà sáng tạo ra. Từ nhận thức này, hắn lấy tơ máu đồng tử hai mắt làm cơ sở, biến chúng thành sợi tơ quy tắc của riêng mình, dung hợp toàn bộ cấm chế xung quanh vào trong mắt — hai mắt chính là cấm chế bổn nguyên. Đạo này tuy giống quy tắc thiên địa nhưng hoàn toàn thuộc về bản thân Vương Lâm, là phương pháp chưa từng có tiền lệ. Tính tới thời điểm ghi nhận, cấm chế bổn nguyên chưa đại thành; muốn đại thành cần khiến quy tắc bản thân trở thành quy tắc thiên địa.","thuocTinh":"Cấm chế / quy tắc","nguonGoc":"Vương Lâm tự ngộ từ nghiên cứu tấm buồm mặt quỷ và quy tắc thiên địa","dacDiem":"Lấy tơ máu đồng tử hai mắt làm cơ sở, hai mắt chính là cấm chế bổn nguyên; bản chất giống quy tắc thiên địa nhưng thuộc về riêng bản thân, là phương pháp từ cổ chí kim chưa ai nghĩ tới. Chưa đại thành — muốn đại thành phải khiến quy tắc bản thân trở thành quy tắc thiên địa.","congNang":["Dung hợp và kiểm soát mọi cấm chế xung quanh, thu nạp vào hai mắt @c1620","Gảy sợi dây quy tắc vô hình tạo vùng băng hàn khổng lồ hoặc hố đen nuốt mọi vật","Tạo trường kiếm hư ảo chứa vô số cấm chế"],"cacTang":[{"ten":"Thành hình (chưa đại thành)","moTa":"Tơ máu đồng tử ngưng tụ thành một sợi chỉ hồng mỗi mắt, có thể dung hợp cấm chế và gảy sợi dây quy tắc","chuong":"@c1620"}],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1620","tangDatToi":"Thành hình (chưa đại thành)","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1620","loai":"xuất hiện","importance":"major","giaiDoan":"Thành hình","text":"Vương Lâm lĩnh ngộ cấm chế bổn nguyên, dùng tơ máu đồng tử làm sợi tơ quy tắc dung hợp mọi cấm chế. Đạo bổn nguyên thứ bảy thành hình, phương pháp từ cổ chí kim chưa ai nghĩ tới. Chưa đại thành.","anchor":"Loại phương pháp này từ cổ chí kim chưa người nào từng nghĩ tới"}]},"capNhatToi":"@c1620","dinhDanh":"goc","nguon":["@c1620"]},{"id":"tran-phap-huyet-mach-tien-nhan","name":"Trận pháp huyết mạch tiên nhân","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Viễn cổ tiên vực","soHuu":["Tứ đại chiến tướng viễn cổ tiên vực"],"blurb":"Trận pháp do tứ đại chiến tướng viễn cổ tiên vực liên thủ cùng vô số tiên nhân bố trí, dùng để tìm kiếm hồn thứ ba.","detail":"Tứ đại chiến tướng viễn cổ tiên vực liên thủ với rất nhiều tiên nhân bố trí trận pháp này, không ngừng tìm kiếm hồn thứ ba trong đại loạn bên ngoài tiên giới.","congNang":["Tìm kiếm hồn thứ ba"],"tabs":{"tienTrinh":[{"chuong":"@c1621","loai":"xuất hiện","importance":"normal","giaiDoan":"Bố trí tìm hồn thứ ba","text":"Tứ đại chiến tướng viễn cổ tiên vực liên thủ cùng vô số tiên nhân bố trí trận pháp huyết mạch tiên nhân, không ngừng tìm kiếm hồn thứ ba.","anchor":"dùng trận pháp này không ngừng tìm kiếm"}]},"nguon":["@c1621"]},{"id":"luan-hoi-nhat-the-thuat","name":"Luân Hồi nhất thể thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thất Thải Tiên Tôn","soHuu":["Thiên Vận Tử"],"blurb":"Luân Hồi nhất thể thuật là thần thông của Thất Thải Tiên Tôn (chưa tu thành), lợi dụng vô số kiếp luân hồi biến mỗi kiếp thành phân thân rồi cắn nuốt lẫn nhau, cuối cùng trộm toàn bộ bổn nguyên và tu vi của kẻ dung hợp phân thân. Thuật này cực kỳ ác độc nhưng tiềm ẩn khả năng bị phản ngược: nếu kẻ bị hại giết được người thi triển thì có thể thôn phệ ngược lại mà tăng trưởng tu vi.","detail":"Luân Hồi nhất thể thuật là thần thông thuộc về Thất Thải Tiên Tôn, song bản thân Thất Thải Tiên Tôn cũng chưa tu thành thuật này. Cơ chế cốt lõi của thuật là thông qua vô số lần luân hồi, biến mỗi kiếp luân hồi thành một phân thân, các phân thân sau đó cắn nuốt lẫn nhau. Khi một phân thân bị ngoại nhân đoạt lấy và dung hợp, người thi triển thuật sẽ trở thành nhất thể với kẻ đó, từ đó cắn nuốt hết toàn bộ bổn nguyên cùng tu vi. Toàn bộ cơ chế của thuật này được Lam Mộng Đạo Tôn tiết lộ cho Vương Lâm, trong đó Lam Mộng Đạo Tôn đánh giá Vương Lâm nắm chắc bốn phần đã mắc thuật này. Thông tin về thuật này Lam Mộng Đạo Tôn nghe được từ Chưởng Tôn. Thuật tuy uy lực ghê gớm nhưng bản chất cực ác độc và tiềm ẩn nguy cơ phản ngược chí mạng cho chính người thi triển.","thuocTinh":"Luân hồi, phân thân, thôn phệ","nguonGoc":"Thần thông của Thất Thải Tiên Tôn, chưa tu thành","dacDiem":"Cực kỳ ác độc, có thể bị phản ngược — nếu kẻ bị hại giết được người thi triển thì thôn phệ ngược tăng tu vi. Thất Thải Tiên Tôn cũng chưa tu thành thuật này.","congNang":["Qua vô số lần luân hồi biến mỗi kiếp thành phân thân, các phân thân cắn nuốt lẫn nhau @c1623","Khi phân thân bị ngoại nhân dung hợp, người thi triển trở thành nhất thể với kẻ đó, cắn nuốt hết bổn nguyên và tu vi @c1623","Kẻ bị hại nếu giết được người thi triển thì có thể thôn phệ ngược lại, tăng trưởng tu vi @c1623"],"nguoiTu":[{"ten":"Thiên Vận Tử","tuChuong":"@c1623","tangDatToi":"Không rõ","trangThai":"đang thi triển (nghi)"}],"tabs":{"tienTrinh":[{"chuong":"@c1623","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Tiết lộ cơ chế hoạt động","text":"Lam Mộng Đạo Tôn tiết lộ toàn bộ cơ chế thuật này cho Vương Lâm: qua vô số luân hồi tạo phân thân cắn nuốt nhau, khi phân thân bị dung hợp thì trộm hết bổn nguyên tu vi. Xác nhận đây là thần thông Thất Thải Tiên Tôn, chưa tu thành. Đánh giá Vương Lâm nắm chắc bốn phần đã mắc thuật.","anchor":"ta nắm chắc bốn phần là ngươi đã nằm trong Luân Hồi nhất thể thuật của người khác rồi"}]},"capNhatToi":"@c1623","nguon":["@c1623"]},{"id":"tam-quang-ho-the-tam-kiem-khai-ha","name":"Tam quang hộ thể, tam kiếm khai hà","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Thanh Lâm"],"blurb":"Thần thông Thanh Lâm thi triển, triệu tập ánh sáng tinh-nguyệt-nhật bao phủ thân hộ thể kiêm tấn công.","detail":"Thanh Lâm triệu tập tam quang (tinh, nguyệt, nhật) bao phủ thân hộ thể, đồng thời tấn công. Khi đối đầu lưỡi hái bảy màu của đạo nhân bảy màu trong Triệu Hà tinh vực, phá vỡ lưỡi hái nhưng bản thân cũng bị chấn.","congNang":["Tam quang (tinh nguyệt nhật) hộ thể","Tam kiếm tấn công"],"nguoiTu":[{"ten":"Thanh Lâm","tuChuong":"@c1623","tangDatToi":"","trangThai":"thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1623","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển lần đầu (trong truyện)","text":"Thanh Lâm thi triển khi đối đầu lưỡi hái bảy màu trong Triệu Hà tinh vực, phá vỡ lưỡi hái nhưng bản thân bị chấn.","anchor":"Tinh, nguyệt, nhật, tam quang hộ thể, tam kiếm khai hà!"}]},"capNhatToi":"@c1623","nguon":["@c1623"]},{"id":"sat-cam-bon-nguyen","name":"Sát cấm bổn nguyên","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Cấm chế bổn nguyên","soHuu":["Vương Lâm"],"blurb":"Sát cấm bổn nguyên là thần thông do Vương Lâm tự ngộ từ cấm chế bổn nguyên, sử dụng tơ máu trong đồng tử tạo cấm chế dạng quy tắc quấn lấy đối phương rồi sắc bén chia lìa thân thể mục tiêu. Chiêu thức được thi triển lần đầu trong đại chiến với Thiên Vận Tử tại Triệu Hà.","detail":"Sát cấm bổn nguyên là thần thông Vương Lâm tự mình lĩnh ngộ, bắt nguồn từ cấm chế bổn nguyên. Khi thi triển, Vương Lâm vuốt hai mắt, hai đồng tử khổng lồ hư ảo đầy tơ máu xuất hiện ở hai bên. Tơ máu bên trong đồng tử ẩn chứa cấm chế, lan ra như mạng nhện quấn lấy đối phương, sau đó trở nên sắc bén có thể chia lìa thân thể mục tiêu. Lần đầu tiên chiêu thức này được sử dụng là trong trận đại chiến với Thiên Vận Tử tại Triệu Hà (@c1624).","thuocTinh":"Cấm chế","nguonGoc":"Vương Lâm tự ngộ từ cấm chế bổn nguyên","dacDiem":"Tơ máu trong đồng tử tạo quy tắc cấm chế, quấn và cắt đối phương","congNang":["Dùng tơ máu trong đồng tử tạo cấm chế dạng quy tắc, lan ra như mạng nhện quấn lấy đối phương (@c1624)","Tơ máu trở nên sắc bén chia lìa thân thể mục tiêu (@c1624)"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1624","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1624","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm thi triển Sát cấm lần đầu trong đại chiến với Thiên Vận Tử tại Triệu Hà, dùng tơ máu đồng tử tạo cấm chế chia lìa thân thể đối phương. Tuy nhiên Thiên Vận Tử chủ động đánh đổi một hồn để đoạt cấm chế bổn nguyên này.","anchor":"Cấm chế bổn nguyên, lấy tơ máu trong đồng tử của ta, tạo thành quy tắc giáng xuống"}]},"capNhatToi":"@c1624","nguon":["@c1624"]},{"id":"luan-hoi-toan-the-thuat","name":"Luân Hồi Toàn Thể Thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Thiên Vận Tử"],"blurb":"Luân Hồi Toàn Thể Thuật là thuật pháp bí ẩn liên quan đến luân hồi, cho phép người tu luyện tỉnh giấc xuyên qua nhiều kiếp. Thiên Vận Tử tiết lộ tên thuật pháp này và cho biết hắn đã tỉnh giấc 98 lần nhờ nó.","detail":"Thuật pháp được Thiên Vận Tử trực tiếp tiết lộ tên gọi tại @c1624, khi hắn nhận xét nó quả thực huyền diệu. Nhờ Luân Hồi Toàn Thể Thuật, Thiên Vận Tử có thể giữ lại ký ức qua các kiếp luân hồi và tỉnh giấc nhiều lần; hắn đã tỉnh giấc 97 lần trước đó, lần hiện tại là lần thứ 98. Qua ký ức tỉnh giấc, Thiên Vận Tử biết mình không phải người đầu tiên tỉnh giấc mà trước hắn đã có hai người khác. Thuật pháp này liên quan mật thiết đến kế hoạch lớn của Thiên Vận Tử.","thuocTinh":"Luân hồi","dacDiem":"Cho phép tỉnh giấc nhiều lần qua các kiếp luân hồi; Thiên Vận Tử đã tỉnh giấc 98 lần nhờ thuật này, và biết rằng trước hắn có hai người khác cũng từng tỉnh giấc.","congNang":["Cho phép người sử dụng tỉnh giấc xuyên qua nhiều kiếp luân hồi, bảo toàn ký ức qua các đời @c1624"],"nguoiTu":[{"ten":"Thiên Vận Tử","tuChuong":"@c1624","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1624","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Tiết lộ tên và bản chất","text":"Thiên Vận Tử tiết lộ tên thuật pháp Luân Hồi Toàn Thể Thuật, cho biết mình đã tỉnh giấc 97 lần trước, lần này là lần thứ 98, không phải người đầu tiên tỉnh giấc.","anchor":"Luân Hồi toàn thể thuật…thuật này quả thực huyền diệu"}]},"capNhatToi":"@c1624","nguon":["@c1624"]},{"id":"than-thong-huyet-mach-dao-co","name":"Thần thông huyết mạch Đạo cổ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Đạo cổ nhất mạch","soHuu":["Vương Lâm"],"blurb":"Thần thông phát động từ huyết mạch Đạo cổ, tạo cuồng phong lực lượng huyết mạch tấn công và phá hoại, là thứ Luân Hồi toàn thể thuật không thể sao chép hay trộm cắp.","detail":"Vương Lâm dùng lực lượng huyết mạch Đạo cổ tạo cuồng phong phá tan đá vụn bốn phía cản Thiên Vận Tử tự điểm mi tâm, sau đó phóng lực lượng Đạo cổ tấn công phân thân Thiên Vận Tử. Đây là ưu thế quyết định: Thiên Vận Tử không có khí tức Đạo cổ, không thể thi triển dù nửa thức thần thông này.","congNang":["Tạo cuồng phong lực lượng huyết mạch tấn công phá hoại @c1625","Không bị Luân Hồi toàn thể thuật sao chép hay trộm @c1625"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1625","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1625","loai":"thi triển","importance":"normal","giaiDoan":"Dùng trong đối đầu Thiên Vận Tử","text":"Vương Lâm phóng cuồng phong huyết mạch Đạo cổ cản Thiên Vận Tử tự điểm mi tâm, sau đó phóng lực lượng Đạo cổ tấn công phân thân. Thiên Vận Tử bị thách thi triển nửa thức nhưng không thể, xác nhận đây là sơ hở trí mạng.","anchor":"Ngươi nếu lúc này có thể thi triển ra nửa thức thần thông huyết mạch Đạo cổ thì Vương mỗ nhận thua"}]},"nguon":["@c1625"]},{"id":"hon-phien","name":"Hồn Phiên","cn":"","aliases":["tấm buồm mặt quỷ"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Hồn Phiên là tấm buồm mặt quỷ của Vương Lâm, có thể bành trướng bao phủ tinh không trong hư ảo, hóa sương mù nhập mi tâm bảo vệ bổn tôn, đồng thời phối hợp Mộng Đạo tạo cấm chế mộng nhập phân thân đối phương để truy tìm bổn tôn.","detail":"Phân thân Vương Lâm triệu ra Hồn Phiên, tấm buồm bành trướng bao phủ toàn bộ khu vực tinh không trong hư ảo. Sau đó Hồn Phiên hóa thành sương mù co rút, hơn phân nửa tiến vào mi tâm bổn tôn Vương Lâm, phần còn lại bao phủ quanh thân bổn tôn để bảo vệ. Trong trận đối đầu với Thiên Vận Tử, Hồn Phiên được dùng làm cấm chế phối hợp cùng Mộng Đạo, mộng nhập ba nghìn phân thân của Thiên Vận Tử nhằm truy tìm bổn tôn đối phương.","congNang":["Bành trướng bao phủ tinh không trong hư ảo @c1626","Hóa sương mù nhập mi tâm bổn tôn, bảo vệ thân bổn tôn @c1626","Phối hợp Mộng Đạo làm cấm chế mộng nhập phân thân đối phương truy tìm bổn tôn @c1626"],"tabs":{"tienTrinh":[{"chuong":"@c1626","loai":"thi triển","importance":"normal","giaiDoan":"Phối hợp Mộng Đạo truy bổn tôn Thiên Vận Tử","text":"Phân thân Vương Lâm triệu Hồn Phiên bao phủ tinh không, hóa sương mù nhập mi tâm bổn tôn. Sau đó dùng làm cấm chế phối hợp Mộng Đạo và khí tức ba nghìn phân thân Thiên Vận Tử, mộng nhập truy tìm bổn tôn.","anchor":"mượn tấm buồm mặt quỷ làm huyễn, mộng nhập ba nghìn phân thân"}]},"nguon":["@c1626"]},{"id":"can-nuot-tinh-giac","name":"Cắn nuốt tỉnh giấc","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Năng lực bản năng","phamCap":"Không rõ","hePhai":"Thiên Vận Tử (thực thể nguyên thủy)","soHuu":["Thiên Vận Tử"],"blurb":"Cơ chế cốt lõi của Thiên Vận Tử: cắn nuốt sinh mạng để hoàn thành mỗi lần thức tỉnh trong luân hồi, đã trải qua hơn chín mươi bảy lần. Lực lượng thôn phệ suy giảm dần theo số lần thức tỉnh.","detail":"Mỗi lần Thiên Vận Tử tỉnh giấc trong vòng luân hồi đều cần cắn nuốt một sinh mạng đã được chọn sẵn. Lực lượng thôn phệ suy giảm rõ rệt theo số lần thức tỉnh: lần thứ ba có thể nuốt cả tu chân tinh, đến lần thứ chín mươi chỉ còn đủ sức nuốt được người thường. Thiên Vận Tử đã trải qua hơn chín mươi bảy lần thức tỉnh, tính từ tinh vực tử vong — thời kỳ trước khi có sinh mạng — cho đến hiện tại. Vương Lâm là người chứng kiến toàn bộ quá trình này.","congNang":["Nuốt sinh mạng đã chọn sẵn để hoàn thành một lần thức tỉnh trong luân hồi @c1627"],"dacDiem":"Lực lượng suy yếu dần theo số lần thức tỉnh: lần thứ ba nuốt được tu chân tinh, lần thứ chín mươi chỉ nuốt được người thường","nguoiTu":[{"ten":"Thiên Vận Tử","tuChuong":"@c1627","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1627","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Lộ toàn bộ cơ chế qua luân hồi","text":"Vương Lâm chứng kiến Thiên Vận Tử cắn nuốt sinh mạng để tỉnh giấc qua hơn chín mươi bảy lần luân hồi. Lực lượng suy yếu dần: lần thứ ba nuốt cả tu chân tinh, lần chín mươi chỉ nuốt người.","anchor":"lần thứ ba có thể nuốt cả tu chân tinh, nhưng lần thứ chín mươi lại chỉ có thế nuốt người"}]},"nguon":["@c1627"]},{"id":"ke-hoach-luan-hoi-van-co","name":"Kế hoạch luân hồi vạn cổ","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật / Âm mưu chiến lược","phamCap":"Không rõ","hePhai":"Thiên Vận Tử","soHuu":["Thiên Vận Tử"],"blurb":"Mưu đồ xuyên suốt vạn cổ của Thiên Vận Tử: nuốt phách nguyên thủy Thất Thải Tiên Tôn rồi để phách đó trưởng thành qua nhiều lần luân hồi, cuối cùng đoạt thân Vương Lâm nhằm mạo danh Thất Thải Tiên Tôn hoàn chỉnh.","detail":"Thiên Vận Tử từ lần thức tỉnh đầu tiên đã nuốt phách nguyên thủy Thất Thải Tiên Tôn, tính toán rằng qua nhiều năm và nhiều lần luân hồi có thể từ phách này suy ra đầy đủ một Thất Thải Tiên Tôn. Tại mốc @c1627, Thiên Vận Tử tuyên bố lần tỉnh giấc sắp tới sẽ là lần cuối cùng và kế hoạch sẽ hoàn thành. Gần ba nghìn phân thân rải khắp tứ đại tinh vực đồng loạt tự hủy bằng cách xuyên mi tâm, toàn bộ hồn phách hợp nhất xông vào phân thân Vương Lâm ở Triệu Hà để đoạt xác, hoàn tất bước mạo danh Thất Thải Tiên Tôn.","congNang":["Nuốt phách nguyên thủy Thất Thải Tiên Tôn, để phách trưởng thành qua nhiều lần luân hồi nhằm tái tạo đầy đủ một Thất Thải Tiên Tôn","Gần ba nghìn phân thân đồng loạt tự hủy (xuyên mi tâm), hồn phách hợp nhất xông vào phân thân Vương Lâm ở Triệu Hà để đoạt xác @c1627"],"nguoiTu":[{"ten":"Thiên Vận Tử","tuChuong":"@c1627","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1627","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Phát động giai đoạn cuối cùng","text":"Thiên Vận Tử tuyên bố lần tỉnh giấc sắp tới sẽ hoàn thành kế hoạch. Gần ba nghìn phân thân tự hủy, hồn phách hợp nhất xông vào phân thân Vương Lâm.","anchor":"tỉnh giấc lần này ta sẽ hoàn thành kế hoạch luân hồi vạn cổ"}]},"nguon":["@c1627"]},{"id":"thien-dao-nhat-the","name":"Thiên đạo nhất thể","cn":"天道一体","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thiên đạo","soHuu":["Thiên Vận Tử"],"blurb":"Thần thông của Thiên Vận Tử, triệu hồi miệng khổng lồ trong tinh không để nuốt mục tiêu, sức mạnh dựa trên khí tức thiên đạo.","detail":"Thiên Vận Tử thi triển bằng câu khẩu quyết Thiên đạo nhất thể, vạn vật thương khung, triệu hồi một cái miệng khổng lồ xuất hiện trong tinh không để nuốt đối thủ. Tuy nhiên khi đối mặt Vương Lâm cầm nửa la bàn (bổn tôn), miệng khổng lồ run rẩy rồi sụp đổ, tiêu tán trong tinh không — cho thấy thần thông này thất bại khi bổn tôn bị khống chế.","nguon":["@c1630"],"tabs":{"tienTrinh":[{"chuong":"@c1630","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển thất bại trước Vương Lâm","text":"Thiên Vận Tử triệu hồi miệng khổng lồ trong tinh không nhưng miệng run rẩy rồi sụp đổ tiêu tán, do Vương Lâm đang cầm bổn tôn (nửa la bàn) của hắn.","anchor":"cái miệng khổng lồ này lại run lên quỷ dị, sau đó sụp đổ, tiêu tán trong tinh không"}]},"nguoiTu":[{"ten":"Thiên Vận Tử","tuChuong":"@c1630","tangDatToi":"Không rõ","trangThai":"tu-vong"}]},{"id":"an-ky-phan-than-vuong-lam","name":"Ấn ký phân thân","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Ấn ký phân thân là ấn ký mà Vương Lâm đặt sẵn trên ngực phân thân của mình, cho phép hắn tiêu hủy toàn bộ đạo, thần, hồn bên trong phân thân ngay cả khi phân thân đã bị kẻ khác chiếm cứ hoàn toàn. Tại chương 1630, Vương Lâm kích hoạt ấn ký này để phản chế Thiên Vận Tử — kẻ đã dung hợp ba nghìn hồn vào phân thân của hắn.","detail":"Ấn ký phân thân được Vương Lâm bố trí sẵn trên ngực phân thân như một thủ đoạn hậu bị đề phòng trường hợp phân thân bị chiếm đoạt. Khi kích hoạt, ấn ký lóe u quang, sóng gợn khuếch tán bao phủ toàn thân đối tượng đang chiếm cứ phân thân. Vương Lâm lần lượt ra lệnh tiêu hủy theo ba tầng: trước tiên là bảy đạo bổn nguyên — hỏa, lôi, sát lục, sinh tử, nhân quả, chân giả, cấm chế — tan rã như tuyết gặp nắng; kế đến nguyên thần bị tiêu tán khiến thân xác trở thành phàm nhân; cuối cùng hồn phách bị tiêu tán, phá vỡ sự dung hợp ba nghìn hồn của Thiên Vận Tử. Ấn ký thể hiện tính toán sâu xa của Vương Lâm, biến lợi thế chiếm cứ phân thân của đối phương thành tử huyệt chí mạng.","nguon":["@c1630"],"congNang":["Tiêu hủy mọi cảm ngộ đại đạo và bổn nguyên trong phân thân dù phân thân đã bị chiếm cứ — bảy đạo bổn nguyên (hỏa, lôi, sát lục, sinh tử, nhân quả, chân giả, cấm chế) tan rã @c1630","Tiêu hủy nguyên thần trong phân thân, biến thân thể thành phàm nhân @c1630","Tiêu hủy hồn phách trong phân thân, phá vỡ sự dung hợp của kẻ chiếm cứ (Thiên Vận Tử) @c1630"],"tabs":{"tienTrinh":[{"chuong":"@c1630","loai":"thi triển","importance":"major","giaiDoan":"Tiêu diệt Thiên Vận Tử","text":"Vương Lâm kích hoạt ấn ký trên ngực phân thân, lần lượt tiêu hủy bảy đạo bổn nguyên, nguyên thần, hồn phách — phá vỡ hoàn toàn sự dung hợp ba nghìn phân thân của Thiên Vận Tử.","anchor":"Ngực hắn lập tức có một đạo ấn ký lóe lên u quang, u quang lóe lên, một luồng sóng gợn từ ấn ký đó khuếch tán ra"}]},"uyLuc":"Lần lượt bóc tách và tiêu hủy triệt để bảy đạo bổn nguyên, nguyên thần và hồn phách bên trong phân thân, khiến kẻ chiếm cứ phân thân — Thiên Vận Tử cùng ba nghìn hồn đã dung hợp — bị phá vỡ hoàn toàn, thân xác rơi về trạng thái phàm nhân.","dacDiem":"Ấn ký được đặt sẵn trên ngực phân thân từ trước, hoạt động theo cơ chế lệnh chủ — Vương Lâm lần lượt ra lệnh tiêu hủy từng tầng (đạo, thần, hồn), khi kích hoạt lóe u quang và khuếch tán sóng gợn bao phủ toàn thân đối tượng."},{"id":"loi-bon-nguyen","name":"Lôi bổn nguyên","loai":"than-thong","loaiLabel":"Bổn nguyên","phamCap":"Bổn nguyên","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Lôi bổn nguyên là bổn nguyên lôi đình, trú ở mắt phải Vương Lâm. Sấm sét tám phương dung nhập mắt phải, ấn ký tia chớp bất diệt hiện ra, cùng Hỏa bổn nguyên tạo thành cặp song nguyên: mắt trái hỏa diễm, mắt phải lôi đình.","detail":"Phân thân Vương Lâm tự xưng chủ nhân lôi đình, triệu hồi lôi bổn nguyên vốn đã tiêu tán trong tinh không trở về. Sấm sét từ tám phương đổ tới, tia chớp vô biên dung nhập mắt phải, điện quang chạy ngoài cơ thể. Ấn ký tia chớp bất diệt hiện ra trong mắt phải. Lôi bổn nguyên cùng Hỏa bổn nguyên tạo thành hai đạo bổn nguyên, phân bố ở hai mắt: mắt trái hỏa diễm, mắt phải lôi đình.","congNang":["Triệu hồi sấm sét từ tám phương dung nhập mắt phải, thu hồi lôi bổn nguyên đã tiêu tán trong tinh không @c1631","Ấn ký tia chớp bất diệt hiện ra trong mắt phải @c1631","Điện quang chạy ngoài cơ thể @c1631"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1631","tangDatToi":"","trangThai":"thu hồi thành công"}],"tabs":{"tienTrinh":[{"chuong":"@c1631","loai":"thi triển","importance":"major","giaiDoan":"Thu hồi lôi bổn nguyên","text":"Phân thân Vương Lâm tự xưng chủ nhân lôi đình, gọi lôi bổn nguyên tiêu tán trong tinh không trở về. Sấm sét dung nhập mắt phải, ấn ký tia chớp bất diệt hiện ra.","anchor":"Trong mắt hắn lúc này liền có ấn ký của tia chớp bất diệt hiện ra"}]},"nguon":["@c1631"],"dacDiem":"Trú ở mắt phải Vương Lâm, đối xứng với Hỏa bổn nguyên ở mắt trái, tạo thành cặp song nguyên lôi – hỏa."},{"id":"dao-hu-bon-nguyen","name":"Đạo Hư Bổn Nguyên","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"Bổn nguyên","soHuu":["Vương Lâm"],"blurb":"Hệ thống bảy đại bổn nguyên mà phân thân Vương Lâm ngưng tụ, bao gồm nhân quả, sát lục, cấm chế và các bổn nguyên khác, vận chuyển trong thân thể khôi phục nguyên thần.","detail":"Phân thân Vương Lâm ngưng tụ bảy đại bổn nguyên từ tinh không vô hình: nhân quả bổn nguyên (mở tay là nhân, nắm tay là quả), sát lục bổn nguyên, cấm chế bổn nguyên cùng các bổn nguyên khác. Bảy đại bổn nguyên vận chuyển trong thân thể khiến nguyên thần biến ảo, khôi phục hoàn toàn trạng thái trước khi thân thể tan nát.","congNang":["Ngưng tụ bổn nguyên từ tinh không vô hình, khôi phục nguyên thần"],"cacTang":[{"ten":"Nhân quả bổn nguyên","moTa":"Bổn nguyên thứ ba — mở tay là nhân, nắm tay là quả","chuong":"@c1632"},{"ten":"Sát lục bổn nguyên","moTa":"Một trong bảy đại bổn nguyên","chuong":"@c1632"},{"ten":"Cấm chế bổn nguyên","moTa":"Một trong bảy đại bổn nguyên","chuong":"@c1632"}],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1632","tangDatToi":"Bảy đại bổn nguyên","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1632","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Phân thân ngưng tụ bảy đại bổn nguyên","text":"Phân thân Vương Lâm ngưng tụ lần lượt bảy đại bổn nguyên bao gồm nhân quả (bổn nguyên thứ ba, mở tay là nhân nắm tay là quả), sát lục, cấm chế và các bổn nguyên khác, vận chuyển trong thân thể khôi phục nguyên thần hoàn toàn.","anchor":"Đạo hư bổn nguyên thứ ba chính là nhân quả.mở tay là nhân, nắm tay là quả"}]},"nguon":["@c1632"]}]};
